﻿import { getSession } from "@/lib/actions/authActions";
import { AdminSidebar } from "@/components/domain/AdminSidebar";
import { redirect } from "next/navigation";
import { getActiveOrders } from "@/lib/actions/adminActions";
import { obterConfiguracoesLoja } from "@/lib/actions/adminSettingsActions";
import { AdminRealtimeProvider } from "@/components/domain/AdminRealtimeProvider";

export default async function AdminLayout({
    children,
}: {
    children: React.ReactNode;
}) {
    const sessionData = await getSession();

    // Proteção centralizada para todas as rotas de admin
    if (!sessionData?.profile?.is_admin) {
        return (
            <div className="flex h-screen items-center justify-center p-6 text-center flex-col bg-background">
                <div className="h-16 w-16 bg-red-100 text-red-600 rounded-xl flex items-center justify-center mb-6 shadow-xl shadow-red-500/10">
                    <svg className="h-10 w-10" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
                    </svg>
                </div>
                <h1 className="text-3xl font-black bg-red-100 text-red-600 p-4 rounded-xl tracking-tighter uppercase italic">NEGADO: VOCÊ NÃO É ADMIN</h1>
                <p className="mt-4 text-gray-500 max-w-md font-medium">Esta área é restrita ao proprietário. Verifique seu nível de acesso no painel do Supabase antes de continuar.</p>
            </div>
        );
    }

    const orders = await getActiveOrders();
    const settings = await obterConfiguracoesLoja();

    return (
        <AdminRealtimeProvider initialOrders={orders as any} storeSettings={settings}>
            <div className="flex min-h-screen bg-gray-50/50 dark:bg-background overflow-hidden">
                <AdminSidebar />
                <main className="flex-1 overflow-x-hidden overflow-y-auto h-screen relative no-scrollbar">
                    {children}
                </main>
            </div>
        </AdminRealtimeProvider>
    );
}

﻿import { getManagementOrders } from "@/lib/actions/adminActions";
import { AdminOrdersManagement } from "@/components/domain/AdminOrdersManagement";
import { ShoppingBag } from "lucide-react";

export const dynamic = "force-dynamic";

export default async function AdminManagementPage() {
    const orders = await getManagementOrders();

    return (
        <div className="flex flex-col min-h-screen bg-gray-50/50 dark:bg-background animate-in fade-in duration-500">
            {/* Header Sticky */}
            <header className="sticky top-0 z-40 bg-white/80 dark:bg-black/80 backdrop-blur-xl border-b border-gray-100 dark:border-gray-800 px-6 pt-[calc(env(safe-area-inset-top,0px)+24px)] pb-6 shadow-sm">
                <div className="max-w-7xl mx-auto flex flex-col sm:flex-row sm:items-center justify-between gap-4">
                    <div className="space-y-1">
                        <h1 className="text-3xl font-black text-foreground tracking-tighter italic uppercase flex items-center gap-3">
                            <ShoppingBag className="h-8 w-8 text-brand" />
                            Gestão de Pedidos
                        </h1>
                        <p className="text-gray-500 font-medium tracking-tight uppercase text-[10px] leading-none">Controle geral, histórico e análise de cancelamentos.</p>
                    </div>

                    <div className="flex items-center gap-6">
                        <div className="flex flex-col items-end">
                            <span className="text-[9px] uppercase font-black text-gray-400">TOTAL PEDIDOS</span>
                            <span className="text-xl font-black text-foreground italic tracking-tighter tabular-nums leading-none">
                                {orders.length.toString().padStart(2, '0')}
                            </span>
                        </div>
                        <div className="h-8 w-px bg-gray-100 dark:bg-gray-800" />
                        <div className="flex flex-col items-end">
                            <span className="text-[9px] uppercase font-black text-red-400">CANCELADOS</span>
                            <span className="text-xl font-black text-red-500 italic tracking-tighter tabular-nums leading-none">
                                {orders.filter(o => o.status === 'CANCELLED').length.toString().padStart(2, '0')}
                            </span>
                        </div>
                    </div>
                </div>
            </header>

            <div className="flex-1">
                <AdminOrdersManagement initialOrders={orders as any} />
            </div>
        </div>
    );
}

﻿import { getActiveOrders } from "@/lib/actions/adminActions";
import { obterConfiguracoesLoja } from "@/lib/actions/adminSettingsActions";
