﻿"use client";

import { useState, useEffect } from "react";
import { createAddress, deleteAddress, setDefaultAddress, updateAddress } from "@/lib/actions/profileActions";
import { Input, Label } from "@/components/core/Input";
import { ArrowLeft, MapPin, Plus, Trash2, CheckCircle2, Loader2, Edit3, X, AlertTriangle, Hash, Landmark, Navigation2 } from "lucide-react";
import { useRouter } from "next/navigation";
import { motion, AnimatePresence } from "framer-motion";

interface Address {
    id: string;
    street: string;
    number: string;
    neighborhood: string;
    city: string;
    complement?: string;
    is_default: boolean;
    cep?: string;
}

export function AddressManager({ initialAddresses }: { initialAddresses: Address[] }) {
    const router = useRouter();
    const [isAdding, setIsAdding] = useState(false);
    const [editingAddress, setEditingAddress] = useState<Address | null>(null);
    const [confirmDeleteId, setConfirmDeleteId] = useState<string | null>(null);
    const [pending, setPending] = useState<string | null>(null);
    const [cepLoading, setCepLoading] = useState(false);

    // Estados para auto-preechimento
    const [street, setStreet] = useState("");
    const [neighborhood, setNeighborhood] = useState("");
    const [city, setCity] = useState("");

    const [cepValue, setCepValue] = useState("");
    const [geoCoords, setGeoCoords] = useState<{ lat: number; lng: number } | null>(null);
    const [geoLoading, setGeoLoading] = useState(false);

    // GPS Native States
    const [gpsLoading, setGpsLoading] = useState(false);
    const [gpsError, setGpsError] = useState<string | null>(null);

    useEffect(() => {
        if (isAdding && editingAddress?.cep) {
            setCepValue(editingAddress.cep);
        } else if (!isAdding) {
            setCepValue("");
        }
    }, [isAdding, editingAddress]);

    const handleCepChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const rawValue = e.target.value;
        const cep = rawValue.replace(/\D/g, "");

        // Formata visualmente
        let formattedCep = cep;
        if (cep.length > 5) {
            formattedCep = cep.replace(/^(\d{5})(\d{1,3})/, "$1-$2");
        }
        setCepValue(formattedCep);

        if (cep.length === 8) {
            setCepLoading(true);
            setGeoCoords(null);
            try {
                const res = await fetch(`https://viacep.com.br/ws/${cep}/json/`);
                const data = await res.json();
                if (!data.erro) {
                    const logradouro = data.logradouro || "";
                    const bairro = data.bairro || "";
                    const localidade = data.localidade || "";
                    const uf = data.uf || "";

                    setStreet(logradouro);
                    setNeighborhood(bairro);
                    setCity(localidade);

                    // Só tenta geocodificar se não tiver pego do GPS ainda
                    if (!geoCoords) {
                        setGeoLoading(true);
                        const enderecos = [
                            [logradouro, bairro, localidade, uf].filter(Boolean).join(", "),
                            [bairro, localidade, uf].filter(Boolean).join(", "),
                            [localidade, uf].filter(Boolean).join(", "),
                        ].filter(Boolean);

                        let foundCoords = null;
                        for (const q of enderecos) {
                            try {
                                const nomRes = await fetch(
                                    `https://nominatim.openstreetmap.org/search?q=${encodeURIComponent(q)}&format=json&limit=1&countrycodes=br`,
                                    { headers: { "User-Agent": "rdos-restaurante-app/1.0" } }
                                );
                                const nomData = await nomRes.json();
                                if (nomData && nomData.length > 0) {
                                    foundCoords = {
                                        lat: parseFloat(nomData[0].lat),
                                        lng: parseFloat(nomData[0].lon),
                                    };
                                    setGeoCoords(foundCoords);
                                    break;
                                }
                            } catch { /* tenta próximo nível */ }
                        }
                        if (!foundCoords) {
                            setGpsError("Coordenadas automáticas não encontradas. Por favor, use o botão de GPS abaixo.");
                        }
                        setGeoLoading(false);
                    }
                }
            } catch (err) {
                console.error("Erro ao buscar CEP:", err);
            } finally {
                setCepLoading(false);
            }
        }
    };

    const handleGetGPS = () => {
        setGpsLoading(true);
        setGpsError(null);
        if ("geolocation" in navigator) {
            navigator.geolocation.getCurrentPosition(
                async (position) => {
                    const lat = position.coords.latitude;
                    const lng = position.coords.longitude;

                    setGeoCoords({ lat, lng });

                    // Busca o endereço correspondente às coordenadas (Reverse Geocoding)
                    try {
                        const res = await fetch(
                            `https://nominatim.openstreetmap.org/reverse?lat=${lat}&lon=${lng}&format=json&addressdetails=1`,
                            { headers: { "User-Agent": "rdos-restaurante-app/1.0" } }
                        );
                        const data = await res.json();

                        if (data && data.address) {
                            const addr = data.address;
                            if (addr.road) setStreet(addr.road);
                            if (addr.suburb || addr.neighbourhood) setNeighborhood(addr.suburb || addr.neighbourhood);
                            if (addr.city || addr.town || addr.village) setCity(addr.city || addr.town || addr.village);
                            if (addr.postcode) {
                                const rawCep = addr.postcode.replace(/\D/g, "");
                                const formattedCep = rawCep.length > 5 ? rawCep.replace(/^(\d{5})(\d{1,3})/, "$1-$2") : rawCep;
                                setCepValue(formattedCep);
                            }
                        }
                    } catch (err) {
                        console.error("Erro ao converter GPS em endereço:", err);
                    }

                    setGpsLoading(false);
                },
                (error) => {
                    console.error("Erro GPS:", error);
                    setGpsError("Não foi possível acessar seu GPS. Verifique as permissões de localização do celular.");
                    setGpsLoading(false);
                },
                { enableHighAccuracy: true, timeout: 15000, maximumAge: 0 }
            );
        } else {
            setGpsError("Seu navegador não suporta GPS.");
            setGpsLoading(false);
        }
    };

    const resetForm = () => {
        setIsAdding(false);
        setEditingAddress(null);
        setStreet("");
        setNeighborhood("");
        setCity("");
        setCepValue("");
    };

    const startEditing = (addr: Address) => {
        setEditingAddress(addr);
        setStreet(addr.street);
        setNeighborhood(addr.neighborhood);
        setCity(addr.city);
        setIsAdding(true);
    };

    async function handleSubmit(formData: FormData) {
        setPending("submit");
        const res = editingAddress
            ? await updateAddress(editingAddress.id, formData)
            : await createAddress(formData);

        setPending(null);
        if (res.success) {
            resetForm();
        } else {
            alert("Erro: " + res.error);
        }
    }

    async function handleConfirmDelete() {
        if (!confirmDeleteId) return;
        setPending(confirmDeleteId);
        await deleteAddress(confirmDeleteId);
        setPending(null);
        setConfirmDeleteId(null);
    }

    async function handleSetDefault(id: string) {
        setPending(id);
        await setDefaultAddress(id);
        setPending(null);
    }

    return (
        <div className="min-h-screen bg-background pb-20">
            <header className="sticky top-0 z-40 flex items-center bg-surface px-4 pt-[calc(env(safe-area-inset-top,0px)+16px)] pb-4 border-b border-gray-100 dark:border-gray-800">
                <button
                    onClick={() => isAdding ? resetForm() : router.back()}
                    className="mr-4 flex h-10 w-10 items-center justify-center rounded-full bg-gray-50 dark:bg-gray-900 border border-gray-100 dark:border-gray-800 hover:bg-gray-100 dark:hover:bg-gray-800 transition-all active:scale-90 shadow-sm"
                >
                    <ArrowLeft className="h-5 w-5 text-foreground" />
                </button>
                <h1 className="text-lg font-bold text-foreground">
                    {editingAddress ? "Editar endereço" : isAdding ? "Novo endereço" : "Meus endereços"}
                </h1>
            </header>

            <main className="max-w-lg mx-auto p-4">
                <AnimatePresence mode="wait">
                    {isAdding ? (
                        <motion.form
                            key="form"
                            initial={{ opacity: 0, x: 20 }}
                            animate={{ opacity: 1, x: 0 }}
                            exit={{ opacity: 0, x: -20 }}
                            action={handleSubmit}
                            className="space-y-4 pt-4"
                        >
                            <div className="space-y-1">
                                <Label>CEP</Label>
                                <Input
                                    name="cep"
                                    maxLength={9}
                                    value={cepValue}
                                    onChange={handleCepChange}
                                    placeholder="Ex: 00000-000"
                                    leftIcon={<MapPin className="h-5 w-5" />}
                                    rightIcon={cepLoading || geoLoading ? <Loader2 className="h-4 w-4 animate-spin text-brand" /> : null}
                                    required
                                />

                                {/* Ação: Obter localização atual do cliente */}
                                <button
                                    type="button"
                                    onClick={handleGetGPS}
                                    disabled={gpsLoading}
                                    className="w-full mt-2 flex items-center justify-center gap-2 py-2.5 px-3 rounded-xl bg-indigo-50 dark:bg-indigo-950/30 text-indigo-600 dark:text-indigo-400 font-bold text-xs uppercase tracking-widest active:scale-[0.98] transition-all border border-indigo-100 dark:border-indigo-900/30"
                                >
                                    {gpsLoading ? (
                                        <Loader2 className="h-4 w-4 animate-spin" />
                                    ) : (
                                        <Navigation2 className="h-4 w-4" />
                                    )}
                                    {gpsLoading ? "Buscando satélites..." : "Usar minha localização atual (GPS)"}
                                </button>

                                {gpsError && (
                                    <div className="flex items-start gap-1 p-2 bg-red-50 dark:bg-red-950/20 rounded-lg mt-2">
                                        <AlertTriangle className="h-3 w-3 text-red-500 mt-0.5 shrink-0" />
                                        <p className="text-[10px] text-red-700 dark:text-red-300 font-medium">{gpsError}</p>
                                    </div>
                                )}

                                {geoCoords && (
                                    <div className="flex items-center gap-1.5 p-2 bg-emerald-50 dark:bg-emerald-950/20 rounded-lg mt-2 border border-emerald-100/50">
                                        <CheckCircle2 className="h-3.5 w-3.5 text-emerald-500" />
                                        <p className="text-[10px] text-emerald-700 dark:text-emerald-400 font-bold tracking-wide uppercase">
                                            Localização Exata p/ Entrega Obtida
                                        </p>
                                    </div>
                                )}
                                {/* Campos hidden com coordenadas para salvar no banco */}
                                <input type="hidden" name="lat" value={geoCoords?.lat ?? ""} />
                                <input type="hidden" name="lng" value={geoCoords?.lng ?? ""} />
                            </div>

                            <div className="grid grid-cols-4 gap-4">
                                <div className="col-span-3 space-y-1">
                                    <Label>Rua / Avenida</Label>
                                    <Input
                                        name="street"
                                        value={street}
                                        onChange={(e) => setStreet(e.target.value)}
                                        placeholder="Ex: Av. Brasil"
                                        leftIcon={<Navigation2 className="h-5 w-5" />}
                                        required
                                    />
                                </div>
                                <div className="col-span-1 space-y-1">
                                    <Label>Nº</Label>
                                    <Input
                                        name="number"
                                        defaultValue={editingAddress?.number || ""}
                                        placeholder="123"
                                        leftIcon={<Hash className="h-4 w-4" />}
                                        className="pl-10"
                                        required
                                    />
                                </div>
                            </div>

                            <div className="space-y-1">
                                <Label>Bairro</Label>
                                <Input
                                    name="neighborhood"
                                    value={neighborhood}
                                    onChange={(e) => setNeighborhood(e.target.value)}
                                    placeholder="Ex: Centro"
                                    leftIcon={<Landmark className="h-5 w-5" />}
                                    required
                                />
                            </div>

                            <div className="space-y-1">
                                <Label>Complemento / Ponto de Ref.</Label>
                                <Input
                                    name="complement"
                                    defaultValue={editingAddress?.complement || ""}
                                    placeholder="Ex: Apto 10 ou Próximo ao mercado"
                                    leftIcon={<Edit3 className="h-5 w-5" />}
                                />
                            </div>

                            <div className="space-y-1">
                                <Label>Cidade</Label>
                                <Input
                                    name="city"
                                    value={city}
                                    onChange={(e) => setCity(e.target.value)}
                                    placeholder="Ex: São Paulo"
                                    leftIcon={<MapPin className="h-5 w-5" />}
                                    required
                                />
                            </div>

                            <label className="flex items-center gap-3 p-4 bg-surface rounded-xl border border-gray-100 dark:border-gray-800 cursor-pointer">
                                <input
                                    type="checkbox"
                                    name="is_default"
                                    defaultChecked={editingAddress?.is_default || false}
                                    className="w-5 h-5 rounded-md border-gray-300 text-brand focus:ring-brand outline-none"
                                />
                                <span className="text-sm font-semibold text-foreground">Definir como principal</span>
                            </label>

                            <button
                                type="submit"
                                disabled={pending === "submit"}
                                className="w-full h-14 mt-8 bg-brand text-white font-bold rounded-xl shadow-lg shadow-brand/20 flex items-center justify-center gap-2 hover:bg-brand-hover active:scale-[0.98] transition-all disabled:opacity-50"
                            >
                                {pending === "submit" ? <Loader2 className="h-5 w-5 animate-spin" /> : editingAddress ? "Salvar alterações" : "Salvar endereço"}
                            </button>
                        </motion.form>
                    ) : (
                        <motion.div
                            key="list"
                            initial={{ opacity: 0, x: -20 }}
                            animate={{ opacity: 1, x: 0 }}
                            exit={{ opacity: 0, x: 20 }}
                            className="space-y-4"
                        >
                            <button
                                onClick={() => setIsAdding(true)}
                                className="w-full h-14 flex items-center justify-center gap-2 rounded-xl border-2 border-dashed border-brand/30 text-brand font-bold text-sm hover:border-brand hover:bg-brand/5 transition-all"
                            >
                                <Plus className="h-5 w-5" />
                                Adicionar novo endereço
                            </button>

                            <div className="space-y-3">
                                {initialAddresses.map((addr) => (
                                    <div
                                        key={addr.id}
                                        className={`p-4 bg-surface rounded-xl border transition-all ${addr.is_default ? "border-brand shadow-md" : "border-gray-100 dark:border-gray-800"}`}
                                    >
                                        <div className="flex justify-between items-start">
                                            <div className="flex gap-3">
                                                <div className={`mt-1 flex h-8 w-8 items-center justify-center rounded-lg ${addr.is_default ? "bg-brand text-white" : "bg-gray-100 dark:bg-gray-800 text-gray-400"}`}>
                                                    <MapPin className="h-4 w-4" />
                                                </div>
                                                <div>
                                                    <h4 className="font-bold text-foreground">{addr.street}, {addr.number}</h4>
                                                    <p className="text-xs text-gray-500">{addr.neighborhood}, {addr.city}</p>
                                                    {addr.complement && <p className="text-xs italic text-gray-400 mt-1">{addr.complement}</p>}
                                                </div>
                                            </div>

                                            <div className="flex items-center gap-1">
                                                <button
                                                    onClick={() => startEditing(addr)}
                                                    className="p-2 text-gray-400 hover:text-brand transition-colors"
                                                >
                                                    <Edit3 className="h-4 w-4" />
                                                </button>
                                                <button
                                                    onClick={() => setConfirmDeleteId(addr.id)}
                                                    className="p-2 text-gray-300 hover:text-red-500 transition-colors"
                                                >
                                                    <Trash2 className="h-4 w-4" />
                                                </button>
                                            </div>
                                        </div>

                                        {!addr.is_default && (
                                            <button
                                                onClick={() => handleSetDefault(addr.id)}
                                                disabled={!!pending}
                                                className="mt-4 w-full h-10 rounded-xl bg-gray-50 dark:bg-gray-900 text-xs font-bold text-gray-500 hover:text-brand transition-all flex items-center justify-center gap-2"
                                            >
                                                {pending === addr.id ? <Loader2 className="h-3 w-3 animate-spin" /> : "Tornar principal"}
                                            </button>
                                        )}

                                        {addr.is_default && (
                                            <div className="mt-4 flex items-center justify-center gap-1.5 text-xs font-bold text-brand">
                                                <CheckCircle2 className="h-3.5 w-3.5" />
                                                Endereço Principal
                                            </div>
                                        )}
                                    </div>
                                ))}

                                {initialAddresses.length === 0 && (
                                    <div className="py-12 text-center">
                                        <p className="text-gray-400 text-sm">Nenhum endereço cadastrado.</p>
                                    </div>
                                )}
                            </div>
                        </motion.div>
                    )}
                </AnimatePresence>
            </main>

            {/* Modal de Confirmação de Exclusão */}
            <AnimatePresence>
                {confirmDeleteId && (
                    <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-black/60 backdrop-blur-sm">
                        <motion.div
                            initial={{ opacity: 0, scale: 0.9, y: 20 }}
                            animate={{ opacity: 1, scale: 1, y: 0 }}
                            exit={{ opacity: 0, scale: 0.9, y: 20 }}
                            className="w-full max-w-sm bg-surface rounded-xl p-6 shadow-2xl border border-gray-100 dark:border-gray-800"
                        >
                            <div className="flex flex-col items-center text-center">
                                <div className="h-16 w-16 bg-red-50 dark:bg-red-950/20 rounded-full flex items-center justify-center mb-4">
                                    <AlertTriangle className="h-8 w-8 text-red-500" />
                                </div>
                                <h3 className="text-xl font-bold text-foreground mb-2">Excluir endereço?</h3>
                                <p className="text-sm text-gray-500 mb-8">
                                    Esta ação não pode ser desfeita. O endereço será removido permanentemente da sua conta.
                                </p>

                                <div className="grid grid-cols-2 gap-3 w-full">
                                    <button
                                        onClick={() => setConfirmDeleteId(null)}
                                        className="h-12 rounded-xl bg-gray-100 dark:bg-gray-800 font-bold text-gray-500 hover:bg-gray-200 transition-all"
                                    >
                                        Cancelar
                                    </button>
                                    <button
                                        onClick={handleConfirmDelete}
                                        disabled={!!pending}
                                        className="h-12 rounded-xl bg-red-500 font-bold text-white shadow-lg shadow-red-500/20 hover:bg-red-600 active:scale-95 transition-all flex items-center justify-center gap-2 disabled:opacity-50"
                                    >
                                        {pending ? <Loader2 className="h-4 w-4 animate-spin" /> : "Sim, excluir"}
                                    </button>
                                </div>
                            </div>
                        </motion.div>
                    </div>
                )}
            </AnimatePresence>
        </div>
    );
}

﻿"use client";

import { useState } from "react";
import { createCategory, createProduct, toggleProductAvailability, createExtra, deleteExtra, updateCategory, deleteCategory, updateProduct, updateCategoryOrder } from "@/lib/actions/adminMenuActions";
import { Card, CardHeader, CardTitle, CardContent } from "@/components/core/Card";
import { Button } from "@/components/core/Button";
import { Input, Label } from "@/components/core/Input";
import { Eye, EyeOff, Plus, Trash2, ChevronDown, ChevronUp, Pencil, X, Check, Tag, Utensils, AlignLeft, Banknote, Coins, Layers } from "lucide-react";
import { cn } from "@/lib/utils";
import { motion, AnimatePresence } from "framer-motion";

export function MenuManager({ categories, products }: { categories: any[], products: any[] }) {
    const [loading, setLoading] = useState(false);
    const [expandedProduct, setExpandedProduct] = useState<string | null>(null);
    const [editingCategory, setEditingCategory] = useState<string | null>(null);
    const [editCategoryName, setEditCategoryName] = useState("");
    const [editCategoryStation, setEditCategoryStation] = useState("MAIN");
    const [catError, setCatError] = useState<string | null>(null);
    const [prodError, setProdError] = useState<string | null>(null);
    const [filterCategory, setFilterCategory] = useState("all");
    const [editingProduct, setEditingProduct] = useState<string | null>(null);
    const [editProductData, setEditProductData] = useState({
        name: "", description: "", price: "", category_id: "", image_url: ""
    });
    const [editProductFile, setEditProductFile] = useState<File | null>(null);

    const filteredProducts = filterCategory === "all"
        ? products
        : products.filter((p: any) => p.category_id === filterCategory);

    const handleCreateCategory = async (e: React.FormEvent<HTMLFormElement>) => {
        e.preventDefault();
        setLoading(true);
        const formData = new FormData(e.currentTarget);
        await createCategory(formData);
        setLoading(false);
        (e.target as HTMLFormElement).reset();
    };

    const handleCreateProduct = async (e: React.FormEvent<HTMLFormElement>) => {
        e.preventDefault();
        setLoading(true);
        setProdError(null);
        const formData = new FormData(e.currentTarget);
        const res = await createProduct(formData);

        if (res?.error) {
            setProdError(res.error);
        } else {
            (e.target as HTMLFormElement).reset();
        }
        setLoading(false);
    };

    const handleToggle = async (productId: string, currentValue: boolean) => {
        await toggleProductAvailability(productId, currentValue);
    };

    const handleCreateExtra = async (e: React.FormEvent<HTMLFormElement>) => {
        e.preventDefault();
        setLoading(true);
        const formData = new FormData(e.currentTarget);
        await createExtra(formData);
        setLoading(false);
        (e.target as HTMLFormElement).reset();
    };

    const handleDeleteExtra = async (extraId: string) => {
        await deleteExtra(extraId);
    };

    const handleStartEdit = (cat: any) => {
        setEditingCategory(cat.id);
        setEditCategoryName(cat.name);
        setEditCategoryStation(cat.station || "MAIN");
        setCatError(null);
    };

    const handleCancelEdit = () => {
        setEditingCategory(null);
        setEditCategoryName("");
        setCatError(null);
    };

    const handleSaveEdit = async (categoryId: string) => {
        if (!editCategoryName.trim()) return;
        setLoading(true);
        setCatError(null);
        const res = await updateCategory(categoryId, editCategoryName.trim(), editCategoryStation);
        if (res?.error) setCatError(res.error);
        else handleCancelEdit();
        setLoading(false);
    };

    const handleSaveProduct = async (productId: string) => {
        if (!editProductData.name.trim()) return;
        setLoading(true);

        const formData = new FormData();
        formData.append("name", editProductData.name.trim());
        formData.append("description", editProductData.description);
        formData.append("price", editProductData.price.replace(",", "."));
        formData.append("category_id", editProductData.category_id);
        formData.append("image_url", editProductData.image_url);
        if (editProductFile) {
            formData.append("image_file", editProductFile);
        }

        const res = await updateProduct(productId, formData);
        if (res?.error) {
            setProdError(res.error);
        } else {
            setEditingProduct(null);
            setEditProductFile(null);
        }
        setLoading(false);
    };

    const handleDeleteCategory = async (categoryId: string) => {
        setCatError(null);
        const res = await deleteCategory(categoryId);
        if (res?.error) setCatError(res.error);
    };

    const handleReorder = async (categoryId: string, direction: 'up' | 'down') => {
        setLoading(true);
        await updateCategoryOrder(categoryId, direction);
        setLoading(false);
    };

    return (
        <div className="space-y-0">

            <div className="grid gap-6 lg:grid-cols-1 xl:grid-cols-2">
                {/* Coluna 1: Categorias */}
                <div className="space-y-6">
                    <Card className="border border-gray-100 dark:border-gray-800 shadow-sm bg-white dark:bg-gray-950 rounded-xl">
                        <CardHeader className="pb-4 border-b border-gray-50 dark:border-gray-900 mx-4 px-0">
                            <CardTitle className="text-xs font-black uppercase italic tracking-tighter flex items-center gap-2 text-[#2A2A2A] dark:text-white">
                                <Plus className="h-4 w-4 text-[#FA0000]" />
                                Nova Categoria
                            </CardTitle>
                        </CardHeader>
                        <CardContent className="pt-6 px-6 pb-6">
                            <form onSubmit={handleCreateCategory} className="space-y-4">
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                    <div className="space-y-1.5">
                                        <Label htmlFor="cat_name" className="text-[10px] font-black uppercase text-gray-400 tracking-widest pl-1">Nome</Label>
                                        <Input
                                            id="cat_name"
                                            name="name"
                                            required
                                            placeholder="Ex: Lanches, Bebidas..."
                                            className="h-11 rounded-xl text-sm font-medium focus:ring-4 ring-red-500/5 bg-gray-50/50 dark:bg-gray-900/50"
                                            leftIcon={<Tag className="h-4 w-4 text-gray-400" />}
                                        />
                                    </div>
                                    <div className="space-y-1.5">
                                        <Label htmlFor="cat_station" className="text-[10px] font-black uppercase text-gray-400 tracking-widest pl-1">Produção (Cozinha)</Label>
                                        <select
                                            name="station"
                                            id="cat_station"
                                            className="w-full h-11 rounded-xl border border-gray-100 dark:border-gray-800 bg-gray-50/50 dark:bg-gray-900/50 px-4 text-[11px] font-black uppercase tracking-tight focus:border-[#FA0000] focus:ring-4 focus:ring-red-500/5 outline-none appearance-none"
                                        >
                                            <option value="MAIN">Montagem (Padrão)</option>
                                            <option value="GRILL">Chapa / Grill</option>
                                            <option value="DRINKS">Bar / Bebidas</option>
                                            <option value="FRY">Fritadeira</option>
                                        </select>
                                    </div>
                                </div>
                                <Button type="submit" disabled={loading} className="w-full bg-[#FA0000] hover:bg-red-600 text-white rounded-xl h-11 text-[10px] font-black uppercase tracking-[0.2em] italic shadow-lg shadow-red-500/10">
                                    {loading ? "Salvando..." : "Adicionar Categoria"}
                                </Button>
                            </form>
                        </CardContent>
                    </Card>

                    <div className="rounded-xl border border-gray-100 dark:border-gray-800 bg-white dark:bg-gray-950 p-8 shadow-sm">
                        <h3 className="text-[10px] font-black uppercase tracking-widest text-gray-400 mb-6 flex items-center gap-2">
                            <Layers className="h-4 w-4" />
                            Categorias Atuais
                        </h3>

                        {catError && (
                            <div className="mb-6 rounded-xl bg-red-50 dark:bg-red-950/20 border border-red-200 dark:border-red-900/30 p-4 text-[10px] font-black uppercase tracking-widest text-[#FA0000] italic">
                                {catError}
                            </div>
                        )}

                        {categories.length === 0 ? (
                            <div className="py-12 text-center opacity-40">
                                <Tag className="h-12 w-12 mx-auto mb-4 text-gray-300" />
                                <p className="text-[10px] font-black uppercase tracking-widest">Vazio</p>
                            </div>
                        ) : (
                            <ul className="space-y-3">
                                {categories.map((c: any) => {
                                    const linkedCount = products.filter((p: any) => p.category_id === c.id).length;
                                    const isEditing = editingCategory === c.id;

                                    return (
                                        <li key={c.id} className="group relative">
                                            <div className={cn(
                                                "p-4 rounded-xl flex items-center gap-4 transition-all border",
                                                isEditing ? "border-[#FA0000] bg-red-50/5 dark:bg-red-950/5" : "bg-gray-50/50 dark:bg-gray-900/50 border-transparent hover:border-gray-200 dark:hover:border-gray-700"
                                            )}>
                                                {isEditing ? (
                                                    <div className="flex flex-col gap-2 w-full animate-in fade-in slide-in-from-left-2 duration-300">
                                                        <div className="flex items-center gap-3">
                                                            <Input
                                                                type="text"
                                                                value={editCategoryName}
                                                                onChange={(e) => setEditCategoryName(e.target.value)}
                                                                className="flex-1 h-10 rounded-lg text-xs font-bold uppercase tracking-tight"
                                                                autoFocus
                                                                onKeyDown={(e) => {
                                                                    if (e.key === "Enter") handleSaveEdit(c.id);
                                                                    if (e.key === "Escape") handleCancelEdit();
                                                                }}
                                                            />
                                                            <div className="flex gap-1">
                                                                <button onClick={() => handleSaveEdit(c.id)} className="h-9 w-9 rounded-lg bg-emerald-500 text-white flex items-center justify-center hover:bg-emerald-600 transition-colors shadow-lg shadow-emerald-500/20">
                                                                    <Check className="h-4 w-4" />
                                                                </button>
                                                                <button onClick={handleCancelEdit} className="h-9 w-9 rounded-lg bg-gray-500 text-white flex items-center justify-center hover:bg-gray-600 transition-colors">
                                                                    <X className="h-4 w-4" />
                                                                </button>
                                                            </div>
                                                        </div>
                                                        <select
                                                            value={editCategoryStation}
                                                            onChange={(e) => setEditCategoryStation(e.target.value)}
                                                            className="w-full h-10 rounded-lg border border-gray-100 dark:border-gray-800 bg-white dark:bg-gray-950 px-3 text-[10px] font-black uppercase focus:border-[#FA0000] outline-none"
                                                        >
                                                            <option value="MAIN">Montagem (Padrão)</option>
                                                            <option value="GRILL">Chapa / Grill</option>
                                                            <option value="DRINKS">Bar / Bebidas</option>
                                                            <option value="FRY">Fritadeira</option>
                                                        </select>
                                                    </div>
                                                ) : (
                                                    <>
                                                        <div className="flex flex-col gap-0.5 opacity-40 group-hover:opacity-100 transition-opacity">
                                                            <button onClick={() => handleReorder(c.id, 'up')} disabled={loading} className="p-0.5 text-gray-400 hover:text-[#FA0000] disabled:opacity-20"><ChevronUp className="h-4 w-4" /></button>
                                                            <button onClick={() => handleReorder(c.id, 'down')} disabled={loading} className="p-0.5 text-gray-400 hover:text-[#FA0000] disabled:opacity-20"><ChevronDown className="h-4 w-4" /></button>
                                                        </div>
                                                        <div className="flex-1 min-w-0">
                                                            <span className="text-sm font-black text-[#2A2A2A] dark:text-gray-100 uppercase tracking-tighter block truncate italic">{c.name}</span>
                                                            <span className="text-[10px] text-gray-400 font-bold uppercase tracking-widest opacity-60">
                                                                {linkedCount} {linkedCount === 1 ? "item" : "itens"} • Estação <span className="text-[#FA0000]">{c.station || "MAIN"}</span>
                                                            </span>
                                                        </div>
                                                        <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-all scale-95 group-hover:scale-100">
                                                            <button onClick={() => handleStartEdit(c)} className="h-9 w-9 rounded-lg text-gray-400 hover:bg-gray-100 dark:hover:bg-gray-800 flex items-center justify-center transition-colors"><Pencil className="h-4 w-4" /></button>
                                                            <button onClick={() => handleDeleteCategory(c.id)} className="h-9 w-9 rounded-lg text-gray-400 hover:bg-red-50 hover:text-[#FA0000] dark:hover:bg-red-950/20 flex items-center justify-center transition-colors"><Trash2 className="h-4 w-4" /></button>
                                                        </div>
                                                    </>
                                                )}
                                            </div>
                                        </li>
                                    );
                                })}
                            </ul>
                        )}
                    </div>
                </div>

                {/* Coluna 2: Produtos */}
                <div className="space-y-6">
                    <Card className={cn(
                        "border border-gray-100 dark:border-gray-800 shadow-sm bg-white dark:bg-gray-950 rounded-xl transition-opacity",
                        categories.length === 0 ? "opacity-40 grayscale pointer-events-none" : ""
                    )}>
                        <CardHeader className="pb-4 border-b border-gray-50 dark:border-gray-900 mx-4 px-0">
                            <CardTitle className="text-xs font-black uppercase italic tracking-tighter flex items-center justify-between w-full text-[#2A2A2A] dark:text-white">
                                <div className="flex items-center gap-2">
                                    <Utensils className="h-4 w-4 text-[#FA0000]" />
                                    Novo Produto
                                </div>
                                {categories.length === 0 && <span className="text-[8px] font-black text-[#FA0000] italic uppercase opacity-60">Crie uma categoria primeiro</span>}
                            </CardTitle>
                        </CardHeader>
                        <CardContent className="pt-6 px-6 pb-6">
                            <form onSubmit={handleCreateProduct} className="space-y-4">
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                    <div className="space-y-1.5">
                                        <Label htmlFor="category_id" className="text-[10px] font-black uppercase text-gray-400 tracking-widest pl-1">Categoria Principal</Label>
                                        <select
                                            name="category_id"
                                            id="category_id"
                                            required
                                            className="w-full h-11 rounded-xl border border-gray-100 dark:border-gray-800 bg-gray-50/50 dark:bg-gray-900/50 px-4 text-[11px] font-black uppercase tracking-tight focus:border-[#FA0000] focus:ring-4 focus:ring-red-500/5 transition-all outline-none appearance-none"
                                        >
                                            <option value="">Selecione...</option>
                                            {categories.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                                        </select>
                                    </div>
                                    <div className="space-y-1.5">
                                        <Label htmlFor="prod_name" className="text-[10px] font-black uppercase text-gray-400 tracking-widest pl-1">Nome do Item</Label>
                                        <Input
                                            id="prod_name"
                                            name="name"
                                            required
                                            placeholder="Ex: X-Burger"
                                            className="h-11 rounded-xl text-[11px] font-medium focus:ring-4 focus:ring-red-500/5 bg-gray-50/50 dark:bg-gray-900/50"
                                            leftIcon={<Utensils className="h-4 w-4 text-gray-400" />}
                                        />
                                    </div>
                                </div>

                                <div className="space-y-1.5">
                                    <Label htmlFor="description" className="text-[10px] font-black uppercase text-gray-400 tracking-widest pl-1">Descrição Comercial</Label>
                                    <Input
                                        id="description"
                                        name="description"
                                        placeholder="Ingredientes e detalhes..."
                                        className="h-11 rounded-xl text-[11px] font-medium focus:ring-4 focus:ring-red-500/5 bg-gray-50/50 dark:bg-gray-900/50 italic"
                                        leftIcon={<AlignLeft className="h-4 w-4 text-gray-400" />}
                                    />
                                </div>

                                <div className="grid grid-cols-2 gap-4">
                                    <div className="space-y-1.5">
                                        <Label htmlFor="price" className="text-[10px] font-black uppercase text-gray-400 tracking-widest pl-1">Preço (R$)</Label>
                                        <Input
                                            id="price"
                                            name="price"
                                            required
                                            type="number"
                                            step="0.01"
                                            min="0"
                                            placeholder="25.90"
                                            className="h-11 rounded-xl text-[11px] font-black tabular-nums focus:ring-4 ring-blue-500/5 bg-gray-50/50 dark:bg-gray-900/50"
                                            leftIcon={<Banknote className="h-4 w-4 text-gray-400" />}
                                        />
                                    </div>
                                    <div className="space-y-1.5">
                                        <Label htmlFor="image_file" className="text-[10px] font-black uppercase text-gray-400 tracking-widest pl-1">Foto Real</Label>
                                        <div className="relative h-11">
                                            <input
                                                type="file"
                                                id="image_file"
                                                name="image_file"
                                                accept="image/*"
                                                className="absolute inset-0 w-full h-full opacity-0 z-10 cursor-pointer"
                                            />
                                            <div className="flex items-center gap-3 h-full px-4 rounded-xl border border-dashed border-gray-200 dark:border-gray-800 bg-gray-50/50 dark:bg-gray-900/50 group-hover:bg-blue-50 transition-colors">
                                                <Plus className="h-4 w-4 text-gray-400" />
                                                <span className="text-[10px] font-black uppercase text-gray-400 tracking-widest">Selecionar Foto</span>
                                            </div>
                                        </div>
                                        <input type="hidden" name="image_url" value="" />
                                    </div>
                                </div>

