                    asChild
                >
                    <Link href="/admin/ratings">
                        VER TODA A REPUTAÇÃO
                    </Link>
                </Button>
            </div>
        </div>
    );
}

﻿"use client";

import { useState, useRef, useEffect, useCallback } from "react";
import { StoreConfig, atualizarConfiguracoesLoja } from "@/lib/actions/adminSettingsActions";
import { salvarZonaEntrega } from "@/lib/actions/deliveryActions";
import { DeliveryZone } from "@/modules/delivery/delivery.types";
import { OpeningHours } from "@/lib/storeUtils";
import { Button } from "@/components/core/Button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/core/Card";
import { Input, Label } from "@/components/core/Input";
import { Textarea } from "@/components/core/Textarea";
import {
    Store,
    Phone,
    MapPin,
    Truck,
    Clock,
    Loader2,
    Info,
    MapPinned,
    Image as ImageIcon,
    Upload,
    Save,
    Timer,
    CalendarDays,
    Check,
    X,
    Pencil,
    Navigation,
} from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import { cn } from "@/lib/utils";
import { toast } from "sonner";

interface AdminSettingsFormProps {
    initialConfig: StoreConfig;
}

type TabType = "identidade" | "logistica" | "horarios";

const fmt = (v: number) =>
    new Intl.NumberFormat("pt-BR", { style: "currency", currency: "BRL" }).format(v);

// ─── Componente principal ─────────────────────────────────────────────────────
export function AdminSettingsForm({ initialConfig }: AdminSettingsFormProps) {
    const [config, setConfig] = useState<StoreConfig>(initialConfig);
    const [loading, setLoading] = useState(false);
    const [activeTab, setActiveTab] = useState<TabType>("identidade");
    const [previewUrl, setPreviewUrl] = useState<string | null>(initialConfig.logo_url || null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    // ─── CEP state ───────────────────────────────────────────────────────────
    const [cep, setCep] = useState("");
    const [cepLoading, setCepLoading] = useState(false);
    const [cepError, setCepError] = useState<string | null>(null);
    const [cepFound, setCepFound] = useState<string | null>(null);
    const [cepPrecision, setCepPrecision] = useState<1 | 2 | 3 | null>(null);

    const queryNominatim = useCallback(async (query: string): Promise<{ lat: number; lng: number } | null> => {
        try {
            const res = await fetch(
                `https://nominatim.openstreetmap.org/search?q=${encodeURIComponent(query)}&format=json&limit=1&countrycodes=br&accept-language=pt-BR`,
                { headers: { "User-Agent": "rdos-restaurante-app/1.0" } }
            );
            const data = await res.json();
            if (!data || data.length === 0) return null;
            return { lat: parseFloat(data[0].lat), lng: parseFloat(data[0].lon) };
        } catch { return null; }
    }, []);

    const fetchCoordsFromCep = useCallback(async (rawCep: string) => {
        const digits = rawCep.replace(/\D/g, "");
        if (digits.length !== 8) return;

        setCepLoading(true);
        setCepError(null);
        setCepFound(null);

        try {
            const viaRes = await fetch(`https://viacep.com.br/ws/${digits}/json/`);
            const viaData = await viaRes.json();

            if (viaData.erro) {
                setCepError("CEP não encontrado.");
                return;
            }

            const { logradouro, bairro, localidade, uf } = viaData;
            const addressString = [logradouro, bairro, `${localidade} - ${uf}`].filter(Boolean).join(", ");

            // Atualiza o endereço de retirada automaticamente
            setConfig(prev => ({ ...prev, pickup_address: addressString }));
            setCepFound(addressString);

            // Busca coordenadas para o restaurante
            const coords = await queryNominatim(`${addressString}, Brasil`);
            if (coords) {
                setConfig(prev => ({ ...prev, lat: coords.lat, lng: coords.lng }));
                setCepPrecision(1);
            }
        } catch {
            setCepError("Erro ao buscar CEP.");
        } finally {
            setCepLoading(false);
        }
    }, [queryNominatim]);

    const handleCepChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const raw = e.target.value.replace(/\D/g, "").slice(0, 8);
        const formatted = raw.length > 5 ? raw.replace(/(\d{5})(\d{1,3})/, "$1-$2") : raw;
        setCep(formatted);
        if (raw.length === 8) fetchCoordsFromCep(raw);
    };

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
        const { name, value, type } = e.target;
        const parsed = type === "number" ? parseFloat(value) : value;
        setConfig((prev: StoreConfig) => ({ ...prev, [name]: parsed }));
    };

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) setPreviewUrl(URL.createObjectURL(file));
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);

        const formData = new FormData();
        formData.append("store_name", config.store_name);
        formData.append("contact_phone", config.contact_phone);
        formData.append("pickup_address", config.pickup_address);
        formData.append("delivery_fee", String(config.delivery_fee));
        formData.append("delivery_radius", String(config.delivery_radius || 0));
        formData.append("min_order_value", String(config.min_order_value));
        formData.append("estimated_time", config.estimated_time);
        formData.append("pickup_estimated_time", config.pickup_estimated_time);
        formData.append("lat", String(config.lat || 0));
        formData.append("lng", String(config.lng || 0));
        formData.append("description", config.description || "");

        if (config.opening_hours) {
            formData.append("opening_hours", JSON.stringify(config.opening_hours));
        }
        if (fileInputRef.current?.files?.[0]) {
            formData.append("logo_file", fileInputRef.current.files[0]);
        }

        const res = await atualizarConfiguracoesLoja(formData);
        if (res.sucesso) {
            toast.success("Configurações salvas com sucesso!");
            setTimeout(() => window.location.reload(), 1000);
        } else {
            toast.error(res.error || "Erro ao salvar configurações.");
        }
        setLoading(false);
    };

    const tabs = [
        { id: "identidade", label: "Identidade", icon: Store },
        { id: "logistica", label: "Logística & Taxas", icon: Truck },
        { id: "horarios", label: "Funcionamento", icon: CalendarDays },
    ];

    return (
        <form onSubmit={handleSubmit} className="space-y-0 pb-20">
            {/* Tab Navigation */}
            <div className="sticky top-0 z-20 bg-white/80 dark:bg-black/94 backdrop-blur-2xl border-b border-gray-200 dark:border-gray-800 -mx-8 px-8 mb-10">
                <div className="flex items-center gap-10 overflow-x-auto no-scrollbar pt-6">
                    {tabs.map((tab) => (
                        <button
                            key={tab.id}
                            type="button"
                            onClick={() => setActiveTab(tab.id as TabType)}
                            className={cn(
                                "relative pb-5 flex items-center gap-2.5 text-[11px] font-black uppercase tracking-[0.2em] transition-all whitespace-nowrap px-1",
                                activeTab === tab.id
                                    ? "text-[#FA0000]"
                                    : "text-gray-500 dark:text-gray-400 hover:text-gray-800 dark:hover:text-gray-200"
                            )}
                        >
                            <tab.icon className={cn("h-4 w-4", activeTab === tab.id ? "text-[#FA0000]" : "text-gray-500 dark:text-gray-400")} />
                            {tab.label}
                            {activeTab === tab.id && (
                                <motion.div
                                    layoutId="admin-settings-tab-underline"
                                    className="absolute bottom-0 left-0 right-0 h-1 bg-[#FA0000] rounded-t-full shadow-[0_-2px_8px_rgba(250,0,0,0.3)]"
                                />
                            )}
                        </button>
                    ))}
                </div>
            </div>

            <div className="max-w-4xl mx-auto px-2">
                <AnimatePresence mode="wait">
                    {/* ── ABA: IDENTIDADE ───────────────────────────────── */}
                    {activeTab === "identidade" && (
                        <motion.div
                            key="identidade"
                            initial={{ opacity: 0, x: -10 }}
                            animate={{ opacity: 1, x: 0 }}
                            exit={{ opacity: 0, x: 10 }}
                            transition={{ duration: 0.3 }}
                            className="space-y-8"
                        >
                            <Card className="border border-gray-200 dark:border-gray-800 shadow-sm bg-white dark:bg-black overflow-hidden rounded-xl">
                                <CardHeader className="pb-8 border-b border-gray-100 dark:border-gray-900 mx-6 px-0 pt-8">
                                    <div className="flex flex-col items-center gap-6">
                                        <div className="relative group">
                                            <div className="h-28 w-28 rounded-xl border-4 border-gray-100 dark:border-gray-900 bg-gray-100 dark:bg-gray-900 flex items-center justify-center overflow-hidden shadow-inner transition-all group-hover:border-[#FA0000]/20">
                                                {previewUrl ? (
                                                    <img src={previewUrl} alt="Preview" className="h-full w-full object-cover" />
                                                ) : (
                                                    <ImageIcon className="h-10 w-10 text-gray-300 dark:text-gray-600" />
                                                )}
                                                <div className="absolute inset-0 bg-black/60 text-white opacity-0 group-hover:opacity-100 transition-opacity flex flex-col items-center justify-center gap-2 backdrop-blur-[2px]">
                                                    <Upload className="h-6 w-6" />
                                                    <span className="text-[8px] font-black uppercase italic">Mudar Logo</span>
                                                </div>
                                            </div>
                                            <input
                                                type="file"
                                                ref={fileInputRef}
                                                className="absolute inset-0 opacity-0 cursor-pointer z-10"
                                                accept="image/*"
                                                onChange={handleFileChange}
                                            />
                                        </div>
                                        <div className="text-center space-y-1">
                                            <CardTitle className="text-xl font-black uppercase italic tracking-tighter text-gray-900 dark:text-white">
                                                Marca & Identidade
                                            </CardTitle>
                                            <p className="text-[10px] text-gray-500 dark:text-gray-400 font-bold uppercase tracking-widest italic">
                                                Como seu restaurante aparece para os clientes
                                            </p>
                                        </div>
                                    </div>
                                </CardHeader>
                                <CardContent className="p-10 space-y-8">
                                    <div className="space-y-3">
                                        <Label className="text-[10px] font-black uppercase text-gray-600 dark:text-gray-400 tracking-widest pl-1">
                                            Nome Fantasia
                                        </Label>
                                        <Input
                                            name="store_name"
                                            value={config.store_name || ""}
                                            onChange={handleChange}
                                            className="h-14 rounded-xl text-base font-bold bg-gray-50 dark:bg-gray-900"
                                            leftIcon={<Store className="h-5 w-5 text-gray-400" />}
                                            placeholder="Ex: Pizzaria Napolitana"
                                        />
                                    </div>
                                    <div className="space-y-3">
                                        <Label className="text-[10px] font-black uppercase text-gray-600 dark:text-gray-400 tracking-widest pl-1">
                                            WhatsApp Oficial
                                        </Label>
                                        <Input
                                            name="contact_phone"
                                            value={config.contact_phone || ""}
                                            onChange={handleChange}
                                            className="h-14 rounded-xl text-base font-bold bg-gray-50 dark:bg-gray-900"
                                            leftIcon={<Phone className="h-5 w-5 text-gray-400" />}
                                            placeholder="Ex: 11 98765-4321"
                                        />
                                    </div>
                                    <div className="space-y-3">
                                        <Label className="text-[10px] font-black uppercase text-gray-600 dark:text-gray-400 tracking-widest pl-1">
                                            Bio / Descrição Comercial
                                        </Label>
                                        <Textarea
                                            name="description"
                                            value={config.description || ""}
                                            onChange={handleChange}
                                            className="min-h-[140px] rounded-xl bg-gray-50 dark:bg-gray-900 p-6 text-sm italic font-medium leading-relaxed"
                                            placeholder="A melhor massa artesanal da região desde 1995..."
                                        />
                                    </div>
                                </CardContent>
                            </Card>
                        </motion.div>
                    )}

                    {/* ── ABA: LOGÍSTICA ────────────────────────────────── */}
                    {activeTab === "logistica" && (
                        <motion.div
                            key="logistica"
                            initial={{ opacity: 0, x: -10 }}
                            animate={{ opacity: 1, x: 0 }}
                            exit={{ opacity: 0, x: 10 }}
                            transition={{ duration: 0.3 }}
                            className="space-y-8"
                        >
                            {/* Grid: Tempos + Regras de Entrega */}
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                                {/* Tempos */}
                                <Card className="border border-gray-200 dark:border-gray-800 shadow-sm bg-white dark:bg-black p-8 rounded-xl space-y-6">
                                    <h3 className="text-[10px] font-black uppercase tracking-widest text-[#FA0000] italic flex items-center gap-3">
                                        <Timer className="h-4 w-4" /> Tempos Estimados
                                    </h3>
                                    <div className="space-y-3">
                                        <Label className="text-[10px] font-black uppercase text-gray-600 dark:text-gray-400 tracking-widest pl-1">
                                            Para Entrega
                                        </Label>
                                        <Input
                                            name="estimated_time"
                                            value={config.estimated_time || ""}
                                            onChange={handleChange}
                                            className="h-12 rounded-xl bg-gray-50 dark:bg-gray-900"
                                            placeholder="Ex: 40-60 min"
                                        />
                                    </div>
                                    <div className="space-y-3">
                                        <Label className="text-[10px] font-black uppercase text-gray-600 dark:text-gray-400 tracking-widest pl-1">
                                            Para Retirada
                                        </Label>
                                        <Input
                                            name="pickup_estimated_time"
                                            value={config.pickup_estimated_time || ""}
                                            onChange={handleChange}
                                            className="h-12 rounded-xl bg-gray-50 dark:bg-gray-900"
                                            placeholder="Ex: 15-20 min"
                                        />
                                    </div>
                                </Card>

                                {/* Regras de Entrega (Preço Fixo) */}
                                <Card className="border border-gray-200 dark:border-gray-800 shadow-sm bg-white dark:bg-black p-8 rounded-xl space-y-6">
                                    <h3 className="text-[10px] font-black uppercase tracking-widest text-[#FA0000] italic flex items-center gap-3">
                                        <Truck className="h-4 w-4" /> Regras de Frete Fixo
                                    </h3>
                                    <div className="space-y-3">
                                        <Label className="text-[10px] font-black uppercase text-gray-600 dark:text-gray-400 tracking-widest pl-1">
                                            Taxa de Entrega (R$)
                                        </Label>
                                        <Input
                                            type="number"
                                            name="delivery_fee"
                                            step="0.01"
                                            value={config.delivery_fee}
                                            onChange={handleChange}
                                            className="h-12 rounded-xl bg-gray-50 dark:bg-gray-900 font-bold"
                                            placeholder="5.00"
                                        />
                                    </div>
                                    <div className="space-y-3">
                                        <Label className="text-[10px] font-black uppercase text-gray-600 dark:text-gray-400 tracking-widest pl-1">
                                            Pedido Mínimo (R$)
                                        </Label>
                                        <Input
                                            type="number"
                                            name="min_order_value"
                                            step="0.01"
                                            value={config.min_order_value}
                                            onChange={handleChange}
                                            className="h-12 rounded-xl bg-gray-50 dark:bg-gray-900 font-bold"
                                            placeholder="20.00"
                                        />
                                    </div>
                                </Card>
                            </div>



                            {/* Endereço de Retirada */}
                            <Card className="border border-gray-200 dark:border-gray-800 shadow-sm bg-white dark:bg-black p-10 rounded-xl space-y-6">
                                <h3 className="text-[10px] font-black uppercase tracking-widest text-[#FA0000] italic flex items-center gap-3">
                                    <MapPinned className="h-4 w-4" /> Localização do Restaurante
                                </h3>

                                <div className="space-y-3">
                                    <Label className="text-[10px] font-black uppercase text-gray-600 dark:text-gray-400 tracking-widest pl-1">
                                        Buscar por CEP
                                    </Label>
                                    <div className="relative">
                                        <Input
                                            type="text"
                                            inputMode="numeric"
                                            value={cep}
                                            onChange={handleCepChange}
                                            className={cn(
                                                "h-14 rounded-xl font-black tracking-widest text-base pl-12",
                                                cepError ? "border-red-500 bg-red-50" : cepFound ? "border-emerald-500 bg-emerald-50" : ""
                                            )}
                                            placeholder="00000-000"
                                            maxLength={9}
                                        />
                                        <div className="absolute left-4 top-1/2 -translate-y-1/2">
                                            {cepLoading ? <Loader2 className="h-5 w-5 animate-spin text-brand" /> : <MapPin className="h-5 w-5 text-gray-400" />}
                                        </div>
                                    </div>
                                    {cepError && <p className="text-[10px] font-bold text-red-500 px-2 italic">{cepError}</p>}
                                    {cepFound && <p className="text-[10px] font-bold text-emerald-600 px-2 italic">Endereço identificado com sucesso!</p>}
                                </div>

                                <div className="space-y-3">
                                    <Label className="text-[10px] font-black uppercase text-gray-600 dark:text-gray-400 tracking-widest pl-1">
                                        Endereço Físico Completo
                                    </Label>
                                    <Input
                                        name="pickup_address"
                                        value={config.pickup_address || ""}
                                        onChange={handleChange}
                                        className="h-14 rounded-xl bg-gray-50 dark:bg-gray-900 text-base font-bold"
                                        leftIcon={<MapPin className="h-5 w-5 text-gray-400" />}
                                        placeholder="Ex: Av. Atlântica, 1500"
                                    />
                                    <p className="text-[10px] text-gray-500 dark:text-gray-400 font-semibold uppercase tracking-widest italic">
                                        Este endereço é preenchido automaticamente ao buscar o CEP acima.
                                    </p>
                                </div>
                            </Card>
                        </motion.div>
                    )}

                    {/* ── ABA: HORÁRIOS ─────────────────────────────────── */}
                    {activeTab === "horarios" && (
                        <motion.div
                            key="horarios"
                            initial={{ opacity: 0, x: -10 }}
                            animate={{ opacity: 1, x: 0 }}
                            exit={{ opacity: 0, x: 10 }}
                            transition={{ duration: 0.3 }}
                            className="space-y-6"
                        >
                            <Card className="border border-gray-200 dark:border-gray-800 shadow-sm bg-white dark:bg-black p-10 rounded-xl">
                                <div className="flex items-center justify-between mb-10">
                                    <div>
                                        <h3 className="text-xl font-black uppercase italic tracking-tighter text-gray-900 dark:text-white">
                                            Horários de Operação
                                        </h3>
                                        <p className="text-[10px] text-gray-500 dark:text-gray-400 font-bold uppercase tracking-widest italic">
                                            Defina as janelas de atendimento semanal
                                        </p>
                                    </div>
                                    <CalendarDays className="h-8 w-8 text-[#FA0000] opacity-20" />
                                </div>

                                <div className="space-y-3">
                                    {["Segunda", "Terça", "Quarta", "Quinta", "Sexta", "Sábado", "Domingo"].map((dia) => {
                                        const currentDay = config.opening_hours?.find((h) => h.day === dia) || {
                                            day: dia,
                                            open: "18:00",
                                            close: "23:00",
                                            closed: false,
                                        };

                                        const handleDayChange = (field: string, value: unknown) => {
                                            const newHours = [...(config.opening_hours || [])];
                                            const index = newHours.findIndex((h: OpeningHours) => h.day === dia);
                                            const updatedDay = { ...currentDay, [field]: value };
                                            if (index >= 0) newHours[index] = updatedDay;
                                            else newHours.push(updatedDay);
                                            setConfig((prev: StoreConfig) => ({ ...prev, opening_hours: newHours }));
                                        };

                                        return (
                                            <div
                                                key={dia}
                                                className={cn(
                                                    "group flex flex-col sm:flex-row items-center justify-between p-5 rounded-xl transition-all border",
                                                    currentDay.closed
                                                        ? "bg-red-50/10 border-red-100/20 opacity-60 grayscale"
                                                        : "bg-gray-50/40 dark:bg-gray-950/40 border-transparent hover:border-gray-200 dark:hover:border-gray-800"
                                                )}
                                            >
                                                <div className="flex items-center gap-4 w-40">
                                                    <span className="text-xs font-black uppercase tracking-widest text-gray-800 dark:text-gray-200 italic">
                                                        {dia}
                                                    </span>
                                                </div>

                                                <div className="flex flex-wrap items-center gap-6 flex-1 justify-end w-full sm:w-auto">
                                                    <label className="flex items-center gap-3 cursor-pointer select-none">
                                                        <input
                                                            type="checkbox"
                                                            checked={currentDay.closed}
                                                            onChange={(e) => handleDayChange("closed", e.target.checked)}
                                                            className="hidden"
                                                        />
                                                        <div className={cn(
                                                            "h-6 w-11 rounded-full p-1 transition-all duration-300",
                                                            currentDay.closed ? "bg-[#FA0000]" : "bg-gray-200 dark:bg-gray-700"
                                                        )}>
                                                            <div className={cn(
                                                                "h-4 w-4 rounded-full bg-white transition-all shadow-sm",
                                                                currentDay.closed ? "translate-x-5" : "translate-x-0"
                                                            )} />
                                                        </div>
                                                        <span className="text-[10px] font-black uppercase text-gray-600 dark:text-gray-400 tracking-widest">
                                                            {currentDay.closed ? "Fechado" : "Aberto"}
                                                        </span>
                                                    </label>

                                                    {!currentDay.closed && (
                                                        <div className="flex items-center gap-2">
                                                            <Input
                                                                type="time"
                                                                value={currentDay.open}
                                                                onChange={(e) => handleDayChange("open", e.target.value)}
                                                                className="h-10 w-28 px-4 rounded-xl font-black text-xs text-center border-none bg-white dark:bg-gray-900 shadow-inner"
                                                            />
                                                            <span className="text-[9px] font-black text-gray-400 mx-1">➜</span>
                                                            <Input
                                                                type="time"
                                                                value={currentDay.close}
                                                                onChange={(e) => handleDayChange("close", e.target.value)}
                                                                className="h-10 w-28 px-4 rounded-xl font-black text-xs text-center border-none bg-white dark:bg-gray-900 shadow-inner"
                                                            />
                                                        </div>
                                                    )}
                                                </div>
                                            </div>
                                        );
                                    })}
                                </div>
                            </Card>
                        </motion.div>
                    )}
                </AnimatePresence>
            </div>

            {/* Barra fixa de salvamento */}
            <div className="fixed bottom-0 left-[280px] right-0 bg-white/80 dark:bg-black/90 backdrop-blur-3xl border-t border-gray-200 dark:border-gray-800/50 p-6 flex justify-center items-center z-40">
                <div className="max-w-4xl w-full flex items-center justify-between px-4">
                    <div className="flex flex-col">
                        <span className="text-[8px] font-black text-gray-500 dark:text-gray-400 uppercase tracking-widest">Estado de Edição</span>
                        <div className="flex items-center gap-2">
                            <div className="h-1.5 w-1.5 rounded-full bg-[#FA0000] animate-pulse" />
                            <span className="text-[10px] font-black uppercase text-gray-800 dark:text-white italic">Alterações não salvas</span>
                        </div>
                    </div>
                    <Button
                        type="submit"
                        disabled={loading}
                        className="h-14 px-12 rounded-xl bg-[#FA0000] hover:bg-red-600 text-white shadow-2xl shadow-red-500/30 font-black italic uppercase tracking-[0.1em] text-xs transition-all active:scale-95 flex items-center gap-3"
                    >
                        {loading ? (
                            <Loader2 className="h-5 w-5 animate-spin" />
                        ) : (
                            <>
                                <Save className="h-5 w-5" />
                                Salvar Configurações
                            </>
                        )}
                    </Button>
                </div>
            </div>
        </form>
    );
}

﻿"use client";

import Link from "next/link";
import { usePathname, useSearchParams } from "next/navigation";
import {
    LayoutDashboard,
    ChefHat,
    ListIcon,
    ShoppingBag,
    LogOut,
    Menu,
    X,
    Settings,
    Bell
} from "lucide-react";
import { useEffect, useState, Suspense } from "react";
import { cn } from "@/lib/utils";
import { UserButton } from "../core/UserButton";
import { obterStatusLoja } from "@/lib/actions/adminSettingsActions";
import { motion } from "framer-motion";
import { useOrdersStore } from "@/lib/ordersStore";

const menuItems = [
    { name: "Painel Geral", href: "/admin", icon: LayoutDashboard },
    { name: "Gestão (Histórico)", href: "/admin/management", icon: ShoppingBag },
    { name: "Cozinha (Pedidos)", href: "/admin/orders", icon: ChefHat },
    { name: "Gestão do Cardápio", href: "/admin/menu", icon: ListIcon },
    { name: "Configurações", href: "/admin/settings", icon: Settings },
];

export function AdminSidebar() {
    return (
        <Suspense fallback={<div className="w-20 xl:w-64 bg-white dark:bg-black h-screen border-r border-gray-100 dark:border-gray-800" />}>
            <AdminSidebarContent />
        </Suspense>
    );
}

function AdminSidebarContent() {
    const pathname = usePathname();
    const searchParams = useSearchParams();
    const isFullscreen = searchParams.get("fullscreen") === "true";

    if (isFullscreen) return null;
    const [isOpen, setIsOpen] = useState(false);
    const [isStoreOpen, setIsStoreOpen] = useState(true);
    const delayedCount = useOrdersStore((state) => state.delayedOrdersCount);
    const refreshDelays = useOrdersStore((state) => state.refreshDelays);

    useEffect(() => {
        async function fetchStatus() {
            const status = await obterStatusLoja();
            setIsStoreOpen(status);
        }
        fetchStatus();

        // Inicia timer para atualizar atrasos a cada 1 minuto
        const interval = setInterval(() => {
            refreshDelays();
        }, 60000);

        return () => clearInterval(interval);
    }, [refreshDelays]);


    return (
        <aside className="relative">
            {/* Botão Mobile */}
            <button
                onClick={() => setIsOpen(!isOpen)}
                className="fixed top-[calc(env(safe-area-inset-top,0px)+16px)] left-4 z-50 rounded-lg bg-surface p-2 shadow-sm border border-gray-100 dark:border-gray-800 lg:hidden text-foreground"
            >
                {isOpen ? <X className="h-6 w-6" /> : <Menu className="h-6 w-6" />}
            </button>

            {/* Backdrop Mobile */}
            {isOpen && (
                <div
                    className="fixed inset-0 z-40 bg-black/40 backdrop-blur-sm lg:hidden"
                    onClick={() => setIsOpen(false)}
                />
            )}

            {/* Sidebar — Elite Navigation */}
            <div className={cn(
                "fixed inset-y-0 left-0 z-50 flex w-72 flex-col bg-white dark:bg-black border-r border-gray-100 dark:border-gray-800 transition-all duration-300 ease-in-out lg:static lg:w-20 xl:w-64 lg:translate-x-0 h-screen",
                isOpen ? "translate-x-0" : "-translate-x-full"
            )}>
                <div className="flex h-24 items-center justify-between lg:justify-center xl:justify-between px-6 mb-4">
                    <div className="flex items-center gap-3">
                        <div className="flex h-11 w-11 shrink-0 items-center justify-center rounded-xl bg-[#FA0000] text-white shadow-xl shadow-red-500/20">
                            <ShoppingBag className="h-6 w-6" />
                        </div>
                        <div className="hidden xl:flex flex-col">
                            <span className="text-xl font-black text-[#2A2A2A] dark:text-white tracking-tighter italic uppercase whitespace-nowrap">
                                RDOS <span className="text-[#FA0000]">BOSS</span>
                            </span>
                            <span className="text-[9px] font-black uppercase text-gray-400 tracking-widest mt-0.5">Painel de Gestão</span>
                        </div>
                    </div>
                </div>

                <div className="flex-1 overflow-y-auto space-y-1">
                    {menuItems.map((item) => {
                        const isActive = pathname === item.href;
                        return (
                            <Link
                                key={item.href}
                                href={item.name.includes("Cozinha") ? `${item.href}?fullscreen=true` : item.href}
                                target={item.name.includes("Cozinha") ? "_blank" : undefined}
                                onClick={() => setIsOpen(false)}
                                className={cn(
                                    "relative flex h-[52px] items-center gap-4 mx-4 xl:mx-4 lg:mx-2 px-5 lg:px-0 xl:px-5 lg:justify-center xl:justify-start rounded-xl text-[11px] font-black uppercase tracking-widest transition-all duration-300 group",
                                    isActive
                                        ? "text-white bg-[#FA0000] shadow-xl shadow-red-500/20 italic"
                                        : "text-gray-500 hover:text-[#FA0000] hover:bg-red-50/50 dark:hover:bg-red-950/10 italic"
                                )}
                            >
                                <item.icon className={cn(
                                    "h-5 w-5 transition-all duration-300 shrink-0",
                                    isActive ? "text-white" : "text-gray-400 group-hover:text-[#FA0000] group-hover:scale-110"
                                )} />
                                <span className="tracking-tight hidden xl:block">{item.name}</span>

                                {/* Badge de Urgência (Apenas para Cozinha) */}
                                {item.name.includes("Cozinha") && delayedCount > 0 && (
                                    <div className={cn(
                                        "absolute right-4 flex h-5 w-5 items-center justify-center rounded-full text-[10px] font-black shadow-lg animate-pulse border-2",
                                        isActive
                                            ? "bg-white text-[#FA0000] border-[#FA0000]"
                                            : "bg-[#FA0000] text-white border-white dark:border-black shadow-red-500/40"
                                    )}>
                                        {delayedCount}
                                    </div>
                                )}
                            </Link>
                        );
                    })}
                </div>

                <div className="p-4 xl:p-6 lg:p-2 border-t border-gray-100 dark:border-gray-800 bg-gray-50/30 dark:bg-gray-900/10">
                    <div className="flex items-center gap-4 lg:gap-0 xl:gap-4 mb-6 lg:justify-center xl:justify-start">
                        <div className="relative shrink-0">
                            <UserButton />
                            <div className="absolute -bottom-0.5 -right-0.5 h-3 w-3 rounded-full bg-emerald-500 border-2 border-white dark:border-black" />
                        </div>
                        <div className="hidden xl:flex flex-col min-w-0">
                            <p className="text-sm font-black text-[#2A2A2A] dark:text-white truncate">Admin Session</p>
                            <span className="text-[10px] font-black text-[#FA0000] uppercase tracking-widest leading-none">Status: Online</span>
                        </div>
                    </div>

                    <Link
                        href="/"
                        className="flex h-11 items-center gap-3 lg:justify-center xl:justify-start rounded-xl px-4 lg:px-0 xl:px-4 text-sm font-bold text-gray-500 hover:bg-red-50 hover:text-red-600 transition-colors"
                    >
                        <LogOut className="h-5 w-5 rotate-180 shrink-0" />
                        <span className="hidden xl:block">Sair do Painel</span>
                    </Link>
                </div>
            </div>
        </aside>
    );
}

﻿"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { useCartStore, CartItem } from "@/store/cartStore";
import { motion, AnimatePresence } from "framer-motion";
import { ArrowLeft, Plus, Minus, Trash2, ShoppingBag, AlertTriangle, Pencil } from "lucide-react";
import Link from "next/link";
import Image from "next/image";

import { Category, Product } from "@/lib/services/catalogService";
import { StoreConfig } from "@/lib/actions/adminSettingsActions";
import { ProductCard } from "./ProductCard";
import { ProductDrawer } from "./ProductDrawer";
import { TrendingUp, Sparkles, PlusCircle } from "lucide-react";
import { cn } from "@/lib/utils";

const fmt = (v: number) =>
    new Intl.NumberFormat("pt-BR", { style: "currency", currency: "BRL" }).format(v);

interface CartViewProps {
    allCategories?: Category[];
    allProducts?: Product[];
    isStoreOpen?: boolean;
    storeSettings?: StoreConfig | null;
}
export function CartView({ allCategories = [], allProducts = [], isStoreOpen = true, storeSettings }: CartViewProps) {
    const router = useRouter();
    const { items, removeItem, incrementQuantity, decrementQuantity, totalPrice, totalItems, clearCart } = useCartStore();
    const [confirmingRemoval, setConfirmingRemoval] = useState<string | null>(null);
    const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
    const [editingItem, setEditingItem] = useState<CartItem | null>(null);
    const [showClearCartModal, setShowClearCartModal] = useState(false);

    if (items.length === 0) {
        return (
            <div className="flex min-h-screen flex-col items-center justify-center p-6 text-center bg-background">
                <div className="flex h-20 w-20 items-center justify-center rounded-full bg-gray-100 dark:bg-gray-800 mb-6">
                    <ShoppingBag className="h-10 w-10 text-gray-400" />
                </div>
                <h2 className="text-xl font-bold text-foreground">Sua sacola está vazia</h2>
                <p className="mt-2 text-sm text-gray-500">Adicione itens do cardápio para começar.</p>
                <button
                    onClick={() => router.push("/")}
                    className="mt-6 h-12 px-8 rounded-xl bg-brand text-white font-semibold hover:bg-brand-hover transition-colors"
                >
                    Ver Cardápio
                </button>
            </div>
        );
    }

    const subtotal = totalPrice();
    const itemCount = totalItems();

    const handleRemoveRequest = (itemId: string) => {
        setConfirmingRemoval(itemId);
    };

    const confirmRemoval = () => {
        if (confirmingRemoval) {
            removeItem(confirmingRemoval);
            setConfirmingRemoval(null);
        }
    };

    return (
        <div className="min-h-screen bg-gray-50 dark:bg-background pb-32">
            {/* Header */}
            <header className="sticky top-0 z-40 bg-surface shadow-sm border-b border-gray-100 dark:border-gray-800">
                <div className="mx-auto w-full max-w-lg px-4 pt-[calc(env(safe-area-inset-top,0px)+16px)] pb-4 flex items-center justify-between">
                    <div className="flex items-center gap-3">
                        <button
                            onClick={() => router.back()}
                            className="flex h-10 w-10 items-center justify-center rounded-full bg-gray-50 dark:bg-gray-900 border border-gray-100 dark:border-gray-800 hover:bg-gray-100 dark:hover:bg-gray-800 transition-all active:scale-90 shadow-sm"
                        >
                            <ArrowLeft className="h-5 w-5 text-foreground" />
                        </button>
                        <h1 className="text-lg font-bold text-foreground">Sacola</h1>
                    </div>

                    <button
                        type="button"
                        onClick={() => setShowClearCartModal(true)}
                        className="text-[10px] font-black uppercase text-red-500 tracking-widest hover:bg-red-50 dark:hover:bg-red-950/20 px-3 py-2 rounded-lg transition-colors"
                    >
                        Limpar
                    </button>
                </div>
            </header>

            <div className="max-w-lg mx-auto">
                {/* Itens adicionados */}
                <section className="bg-surface mx-4 mt-4 rounded-xl shadow-sm border border-gray-100 dark:border-gray-800">
                    <h2 className="font-bold text-foreground px-4 pt-4 pb-2">Itens adicionados</h2>

                    <AnimatePresence initial={false}>
                        {items.map((item) => {
                            const extrasTotal = item.extras?.reduce((a, e) => a + e.price, 0) || 0;
                            const unitTotal = item.product.price + extrasTotal;
                            const lineTotal = unitTotal * item.quantity;

                            return (
                                <motion.div
                                    key={item.id}
                                    layout
                                    initial={{ opacity: 0, height: 0 }}
                                    animate={{ opacity: 1, height: "auto" }}
                                    exit={{ opacity: 0, height: 0 }}
                                    className="border-b border-gray-50 dark:border-gray-800 last:border-0"
                                >
                                    <div className="flex gap-4 p-5">
                                        {/* Imagem do produto */}
                                        <button
                                            onClick={() => {
                                                setSelectedProduct(item.product);
                                                setEditingItem(item);
                                            }}
                                            className="relative h-20 w-20 shrink-0 overflow-hidden rounded-xl bg-gray-50 dark:bg-gray-800 border border-gray-100 dark:border-gray-800 hover:scale-95 transition-transform group/img"
                                        >
                                            {item.product.image_url ? (
                                                <Image
                                                    src={item.product.image_url}
                                                    alt={item.product.name}
                                                    fill
                                                    className="object-cover"
                                                    sizes="80px"
                                                />
                                            ) : (
                                                <div className="flex h-full w-full items-center justify-center text-gray-300">
                                                    <ShoppingBag className="h-8 w-8" />
                                                </div>
                                            )}
                                            {/* Ícone de Lápis - Sempre visível para mobile */}
                                            <div className="absolute inset-0 bg-black/10 flex items-center justify-center transition-opacity">
                                                <div className="bg-white/95 dark:bg-black/95 p-1.5 rounded-full shadow-md border border-gray-100 dark:border-gray-800">
                                                    <Pencil className="h-3 w-3 text-brand" />
                                                </div>
                                            </div>
                                        </button>

                                        {/* Info */}
                                        <div className="flex-1 min-w-0 flex flex-col justify-between py-0.5">
                                            <button
                                                onClick={() => {
                                                    setSelectedProduct(item.product);
                                                    setEditingItem(item);
                                                }}
                                                className="text-left group"
                                            >
                                                <div className="flex justify-between items-start">
                                                    <h3 className="font-semibold text-sm text-foreground leading-tight line-clamp-2 group-hover:text-brand transition-colors">{item.product.name}</h3>
                                                </div>

                                                {item.extras && item.extras.length > 0 && (
                                                    <div className="flex flex-col gap-0.5 mt-0.5">
                                                        {item.extras.map((extra, idx) => (
                                                            <div key={idx} className="flex justify-between items-center pr-2">
                                                                <p className="text-[10px] font-bold uppercase text-gray-500 tracking-tight leading-none group-hover:text-gray-600 transition-colors">
                                                                    + {extra.name}
                                                                </p>
                                                                <span className="text-[10px] font-black italic text-brand/70 tracking-tighter">{fmt(extra.price)}</span>
                                                            </div>
                                                        ))}
                                                    </div>
                                                )}
                                            </button>

                                            <div className="flex justify-between items-center mt-auto pt-1">
                                                <motion.p
                                                    key={lineTotal}
                                                    initial={{ opacity: 0.5, y: -2 }}
                                                    animate={{ opacity: 1, y: 0 }}
                                                    className="text-base font-bold text-foreground tracking-tighter"
                                                >
                                                    {fmt(lineTotal)}
                                                </motion.p>

                                                {/* Controles de quantidade */}
                                                <div className="flex items-center gap-1 bg-gray-50 dark:bg-gray-950 p-1 rounded-xl border border-gray-100 dark:border-gray-800">
                                                    <motion.button
                                                        whileTap={{ scale: 0.9 }}
                                                        onClick={() => item.quantity > 1 ? decrementQuantity(item.id) : handleRemoveRequest(item.id)}
                                                        className="flex h-7 w-7 items-center justify-center rounded-lg hover:bg-white dark:hover:bg-gray-800 text-brand transition-all"
                                                    >
                                                        {item.quantity > 1 ? (
                                                            <Minus className="h-3.5 w-3.5" />
                                                        ) : (
                                                            <Trash2 className="h-3.5 w-3.5" />
                                                        )}
                                                    </motion.button>

                                                    <AnimatePresence mode="wait">
                                                        <motion.span
                                                            key={item.quantity}
                                                            initial={{ opacity: 0, scale: 0.8 }}
                                                            animate={{ opacity: 1, scale: 1 }}
                                                            exit={{ opacity: 0, scale: 0.8 }}
                                                            className="w-6 text-center text-xs font-black text-foreground"
                                                        >
                                                            {item.quantity}
                                                        </motion.span>
                                                    </AnimatePresence>

                                                    <motion.button
                                                        whileTap={{ scale: 0.9 }}
                                                        onClick={() => incrementQuantity(item.id)}
                                                        className="flex h-7 w-7 items-center justify-center rounded-lg hover:bg-white dark:hover:bg-gray-800 text-brand transition-all"
                                                    >
                                                        <Plus className="h-3.5 w-3.5" />
                                                    </motion.button>
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                </motion.div>
                            );
                        })}
                    </AnimatePresence>
                </section>

                {/* Adicionar mais itens */}
                <div className="px-4 mt-6">
                    <Link
                        href="/"
                        className="flex items-center justify-center gap-2 w-full h-12 rounded-xl bg-transparent text-brand font-bold text-sm hover:bg-brand/5 transition-all active:scale-95"
                    >
                        <Plus className="h-4 w-4" />
                        Adicionar mais itens
                    </Link>
                </div>

                {/* Upsell / Sugestões */}
                {allProducts.length > 0 && (
                    <section className="mt-10 px-4">
                        {(() => {
                            const cartCategoryIds = new Set(items.map(i => i.product.category_id));
                            const missingCategories = allCategories.filter(c => !cartCategoryIds.has(c.id));

                            let sectionTitle = "Combine com seu pedido 🍟";
                            let sectionIcon = <Sparkles className="h-5 w-5" />;
                            let productsToShow: Product[] = [];

                            if (missingCategories.length > 0) {
                                const targetCategory = missingCategories.find(c =>
                                    c.name.toLowerCase().includes('acompanhamento') ||
                                    c.name.toLowerCase().includes('bebida')
                                ) || missingCategories[0];

                                sectionTitle = `Combine com seu pedido 🍟`;
                                sectionIcon = <PlusCircle className="h-5 w-5" />;
                                productsToShow = allProducts.filter(p => p.category_id === targetCategory.id).slice(0, 6);
                            } else {
                                sectionTitle = "Os mais pedidos ✨";
                                productsToShow = allProducts.slice(0, 6);
                            }

                            if (productsToShow.length === 0) return null;

                            return (
                                <div className="space-y-4">
                                    <div className="flex flex-col gap-1 px-1">
                                        <div className="flex items-center gap-2 text-foreground">
                                            <h3 className="font-black text-xl italic uppercase tracking-tighter">{sectionTitle}</h3>
                                        </div>
                                        <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest leading-none">Clientes geralmente pedem junto</p>
                                    </div>

                                    <div className="flex gap-4 overflow-x-auto pb-4 no-scrollbar -mx-4 px-4 scroll-smooth">
                                        {productsToShow.map((product) => (
                                            <div key={`upsell-${product.id}`} className="min-w-[200px] shrink-0">
                                                <ProductCard
                                                    product={product}
                                                    onAdd={(p) => isStoreOpen && setSelectedProduct(p)}
                                                    isCompact
                                                    isStoreOpen={isStoreOpen}
                                                />
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            );
                        })()}
                    </section>
                )}



                {/* Resumo de valores & Ação (Fixo no Rodapé - Fiel à Ref 2 com Ícone Brand) */}
                <section className="fixed bottom-0 left-0 right-0 z-40 bg-white dark:bg-black border-t border-gray-100 dark:border-gray-800 p-5 pb-[calc(env(safe-area-inset-bottom,0px)+12px)] shadow-[0_-10px_30px_rgba(0,0,0,0.05)]">
                    <div className="max-w-lg mx-auto flex items-center justify-between gap-4">
                        <div className="flex flex-col">
                            <span className="text-sm font-medium text-gray-500 dark:text-gray-400">Subtotal</span>
                            <div className="flex items-baseline gap-1.5">
                                <motion.span
                                    key={subtotal}
                                    initial={{ opacity: 0.8 }}
                                    animate={{ opacity: 1 }}
                                    className="text-2xl font-bold text-gray-900 dark:text-white tracking-tight"
                                >
                                    {fmt(subtotal)}
                                </motion.span>
                                <span className="text-sm font-medium text-gray-500 dark:text-gray-400">
                                    / {itemCount} {itemCount === 1 ? "item" : "itens"}
                                </span>
                            </div>
                        </div>

                        <button
                            onClick={() => isStoreOpen && router.push("/checkout")}
                            disabled={!isStoreOpen || subtotal < (storeSettings?.min_order_value || 0)}
                            className={cn(
                                "px-10 h-14 rounded-2xl font-semibold text-lg transition-all active:scale-95 shadow-lg flex items-center justify-center gap-3 relative overflow-hidden group",
                                isStoreOpen && subtotal >= (storeSettings?.min_order_value || 0)
                                    ? "bg-brand text-white shadow-brand/20"
                                    : "bg-gray-100 dark:bg-gray-900 text-gray-400 dark:text-gray-600 cursor-not-allowed shadow-none"
                            )}
                        >
                            <span className="relative z-10">
                                {!isStoreOpen ? "Loja Fechada" : "Continuar"}
                            </span>
                            {isStoreOpen && subtotal >= (storeSettings?.min_order_value || 0) && (
                                <>
                                    <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/10 to-transparent translate-x-[-200%] group-hover:translate-x-[200%] transition-transform duration-1000" />
                                    <motion.div
                                        animate={{ x: [0, 4, 0] }}
                                        transition={{ repeat: Infinity, duration: 2 }}
                                    >
                                        <ShoppingBag className="h-5 w-5" />
                                    </motion.div>
                                </>
                            )}
                        </button>
                    </div>
                </section>
            </div>

            {/* Modal de Confirmação de Remoção */}
            <AnimatePresence>
                {confirmingRemoval && (
                    <div className="fixed inset-0 z-[100] flex items-center justify-center p-6">
                        <motion.div
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            exit={{ opacity: 0 }}
                            onClick={() => setConfirmingRemoval(null)}
                            className="absolute inset-0 bg-black/60 backdrop-blur-sm"
                        />
                        <motion.div
                            initial={{ opacity: 0, scale: 0.9, y: 20 }}
                            animate={{ opacity: 1, scale: 1, y: 0 }}
                            exit={{ opacity: 0, scale: 0.9, y: 20 }}
                            className="relative w-full max-w-sm overflow-hidden rounded-xl bg-surface p-6 shadow-2xl dark:bg-gray-900 border border-gray-100 dark:border-gray-800"
                        >
                            <div className="flex flex-col items-center text-center">
                                <div className="mb-4 flex h-16 w-16 items-center justify-center rounded-xl bg-red-100 dark:bg-red-950/30 text-red-600">
                                    <AlertTriangle className="h-8 w-8" />
                                </div>
                                <h3 className="text-lg font-bold text-foreground">Remover item?</h3>
                                <p className="mt-2 text-sm text-gray-500">
                                    Deseja realmente remover este item da sua sacola?
                                </p>

                                <div className="mt-8 flex w-full gap-3">
                                    <button
                                        onClick={() => setConfirmingRemoval(null)}
                                        className="flex-1 h-12 rounded-xl bg-gray-100 dark:bg-gray-800 text-foreground font-bold text-sm hover:bg-gray-200 transition-colors"
                                    >
                                        Cancelar
                                    </button>
                                    <button
                                        onClick={confirmRemoval}
                                        className="flex-1 h-12 rounded-xl bg-red-600 text-white font-bold text-sm hover:bg-red-700 transition-colors shadow-lg shadow-red-600/20"
                                    >
                                        Remover
                                    </button>
                                </div>
                            </div>
                        </motion.div>
                    </div>
                )}
            </AnimatePresence>

            {/* Alerta de Pedido Mínimo (Fixo acima do resumo) */}
            {isStoreOpen && storeSettings && subtotal < (storeSettings.min_order_value || 0) && (
                <div className="fixed bottom-[130px] left-1/2 -translate-x-1/2 w-[calc(100%-32px)] max-w-lg z-30 animate-in slide-in-from-bottom duration-500">
                    <div className="bg-red-50/90 dark:bg-red-950/80 backdrop-blur-xl border border-red-100/30 dark:border-red-800/30 p-4 rounded-2xl shadow-2xl flex items-center gap-4">
                        <div className="h-10 w-10 rounded-xl bg-red-500 text-white flex items-center justify-center shrink-0 shadow-lg shadow-red-500/20">
                            <AlertTriangle className="h-5 w-5" />
                        </div>
                        <div className="flex-1">
                            <p className="text-[10px] font-black uppercase text-red-500 dark:text-red-400 leading-none tracking-widest italic mb-1">Pedido Mínimo</p>
                            <p className="text-sm font-bold text-red-700 dark:text-red-100 tracking-tight leading-snug">
                                Adicione mais <span className="font-black italic">{fmt(storeSettings.min_order_value - subtotal)}</span> para continuar.
                            </p>
                        </div>
                    </div>
                </div>
            )}



            <ProductDrawer
                product={selectedProduct}
                editingItem={editingItem}
                onClose={() => {
                    setSelectedProduct(null);
                    setEditingItem(null);
                }}
                isStoreOpen={isStoreOpen}
            />

            {/* Clear Cart Confirmation Modal */}
            <AnimatePresence>
                {showClearCartModal && (
                    <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 sm:p-4">
                        <motion.div
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            exit={{ opacity: 0 }}
                            onClick={() => setShowClearCartModal(false)}
                            className="absolute inset-0 bg-black/60 backdrop-blur-md"
                        />

                        <motion.div
                            initial={{ opacity: 0, scale: 0.9, y: 20 }}
                            animate={{ opacity: 1, scale: 1, y: 0 }}
                            exit={{ opacity: 0, scale: 0.9, y: 20 }}
                            className="relative w-full max-w-sm bg-white dark:bg-gray-900 rounded-xl p-8 text-center shadow-2xl border border-gray-100 dark:border-gray-800"
                        >
                            <div className="mx-auto mb-6 flex h-20 w-20 items-center justify-center rounded-full bg-red-50 dark:bg-red-950/30 text-red-500 shadow-inner">
                                <AlertTriangle className="h-10 w-10" />
                            </div>

                            <h2 className="text-2xl font-black text-foreground italic uppercase tracking-tighter leading-tight mb-3">
                                Limpar Carrinho?
                            </h2>

                            <p className="text-sm font-medium text-gray-500 dark:text-gray-400 mb-8 px-2">
                                Todos os itens serão removidos e você voltará para o cardápio. Deseja continuar?
                            </p>

                            <div className="space-y-3">
                                <button
                                    onClick={() => {
                                        clearCart();
                                        router.push("/");
                                    }}
                                    className="w-full h-14 rounded-xl bg-red-500 text-white font-black uppercase italic tracking-widest shadow-lg shadow-red-500/20 hover:scale-[1.02] active:scale-95 transition-all"
                                >
                                    Sim, Limpar Tudo
                                </button>

                                <button
                                    onClick={() => setShowClearCartModal(false)}
                                    className="w-full h-12 rounded-xl text-[10px] font-black uppercase tracking-widest text-gray-400 hover:text-foreground transition-all"
                                >
                                    Cancelar
                                </button>
                            </div>
                        </motion.div>
                    </div>
                )}
            </AnimatePresence>
        </div>
    );
}

﻿"use client";

import { useState, useEffect, useRef, useCallback } from "react";
import Link from "next/link";
import Image from "next/image";
import { Category, Product } from "@/lib/services/catalogService";
import { StickyCategoryBar } from "./StickyCategoryBar";
import { ProductCard } from "./ProductCard";
import { FloatingCart } from "./FloatingCart";
import { ProductDrawer } from "./ProductDrawer";
import { TrendingUp, Sparkles, PlusCircle, Search, Info, Clock, Wallet, Bike, Star, Plus } from "lucide-react";
import { UserButton } from "../core/UserButton";
import { Input } from "@/components/core/Input";
import { StoreConfig } from "@/lib/actions/adminSettingsActions";
import { motion } from "framer-motion";
import { cn } from "@/lib/utils";

interface CatalogViewProps {
    categories: Category[];
    products: Product[];
    isStoreOpen?: boolean;
    storeSettings?: StoreConfig | null;
    ratingStats?: {
        averageProduct: number;
        averageDelivery: number;
        total: number;
    };
}

export function CatalogView({ categories, products, isStoreOpen = true, storeSettings, ratingStats }: CatalogViewProps) {
    const [activeCategory, setActiveCategory] = useState<string | null>(
        categories.length > 0 ? categories[0].id : null
    );
    const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
    const [searchQuery, setSearchQuery] = useState("");
    const isScrollingRef = useRef(false);
    const [scrolled, setScrolled] = useState(false);

    // Monitor de Scroll para o Header Sticky
    useEffect(() => {
        const handleScroll = () => {
            setScrolled(window.scrollY > 20);
        };
        window.addEventListener("scroll", handleScroll);
        return () => window.removeEventListener("scroll", handleScroll);
    }, []);

    // Filtragem por busca
    const filteredProductsBySearch = products.filter(p =>
        p.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
        p.description?.toLowerCase().includes(searchQuery.toLowerCase())
    );

    const filteredCategoriesBySearch = searchQuery
        ? categories.filter(cat => filteredProductsBySearch.some(p => p.category_id === cat.id))
        : categories;

    // Scroll suave ao clicar na categoria
    const handleSelectCategory = useCallback((categoryId: string) => {
        setSearchQuery(""); // Limpa busca ao trocar categoria
        setActiveCategory(categoryId);
        isScrollingRef.current = true;

        const el = document.getElementById(`section-${categoryId}`);
        if (el) {
            const offset = 120; // Altura do header encolhido + margens
            const bodyRect = document.body.getBoundingClientRect().top;
            const elementRect = el.getBoundingClientRect().top;
            const elementPosition = elementRect - bodyRect;
            const offsetPosition = elementPosition - offset;

            window.scrollTo({
                top: offsetPosition,
                behavior: "smooth"
            });

            setTimeout(() => {
                isScrollingRef.current = false;
            }, 800);
        }
    }, []);

    // IntersectionObserver: detecta automaticamente qual seção está visível
    useEffect(() => {
        if (searchQuery) return; // Desativa auto-scroll enquanto busca p/ não pular seções

        const sectionIds = categories
            .map((cat) => `section-${cat.id}`);

        const observer = new IntersectionObserver(
            (entries) => {
                if (isScrollingRef.current) return;

                for (const entry of entries) {
                    if (entry.isIntersecting) {
                        const id = entry.target.id.replace("section-", "");
                        setActiveCategory(id);
                        break;
                    }
                }
            },
            {
                rootMargin: "-100px 0px -60% 0px",
                threshold: 0,
            }
        );

        sectionIds.forEach((id) => {
            const el = document.getElementById(id);
            if (el) observer.observe(el);
        });

        return () => observer.disconnect();
    }, [categories, products, searchQuery]);

    return (
        <div className="min-h-screen bg-background pb-32">
            {/* Branding Header - Agora rolável com a página */}
            <header className="bg-transparent py-8 pt-[calc(env(safe-area-inset-top,0px)+24px)] px-5">
                <div className="max-w-lg mx-auto flex items-center justify-between">
                    <motion.div
                        initial={{ opacity: 0, y: -10 }}
                        animate={{ opacity: 1, y: 0 }}
                        className="flex items-center gap-3 cursor-pointer group active:scale-95 transition-all"
                        onClick={() => window.location.href = "/ratings"}
                    >
                        {/* Logo Circular com Borda Brand */}
                        <div className="relative rounded-full border-2 border-brand p-0.5 bg-white overflow-hidden shadow-sm h-11 w-11">
                            {storeSettings?.logo_url ? (
                                <Image src={storeSettings.logo_url} alt="Logo" fill className="object-cover rounded-full" />
                            ) : (
                                <div className="h-full w-full bg-brand flex items-center justify-center rounded-full">
                                    <span className="text-white font-black text-xs">{storeSettings?.store_name?.charAt(0) || "S"}</span>
                                </div>
                            )}
                        </div>

                        {/* Nome da loja */}
                        <div className="flex flex-col">
                            <h1 className="font-black tracking-tighter leading-none text-color-primary text-display">
                                {storeSettings?.store_name || "SMASH GOURMET"}
                            </h1>
                            <div className="flex items-center gap-2 mt-0.5">
                                <div className="flex items-center gap-1">
                                    <div className={cn(
                                        "h-1.5 w-1.5 rounded-full",
                                        isStoreOpen ? "bg-[#00C853] animate-pulse-glow" : "bg-gray-400"
                                    )} />
                                    <span className={cn(
                                        "text-[11px] font-bold uppercase tracking-tight",
                                        isStoreOpen ? "text-[#00C853]" : "text-gray-400"
                                    )}>
                                        {isStoreOpen ? "Aberto agora" : "Fechado"}
                                    </span>
                                </div>
                                {ratingStats && ratingStats.total > 0 && (
                                    <div className="flex items-center gap-1 border-l border-gray-200 dark:border-gray-800 pl-2">
                                        <span className="text-[10px] font-black">{ratingStats.averageProduct}</span>
                                        <Star className="h-2.5 w-2.5 fill-amber-500 text-amber-500" />
                                        <span className="text-[10px] text-gray-400 font-bold">({ratingStats.total})</span>
                                    </div>
                                )}
                            </div>
                        </div>
                    </motion.div>

                    <Link
                        href="/ratings"
                        className="flex items-center gap-1.5 px-3 py-1.5 rounded-full bg-gray-50 hover:bg-gray-100 dark:bg-gray-800 dark:hover:bg-gray-700 transition-colors text-brand"
                    >
                        <Plus className="h-3.5 w-3.5" />
                        <span className="text-[10px] font-black uppercase tracking-widest text-color-primary">Informações</span>
                    </Link>
                </div>
            </header>

            <div className="px-5 mb-8">
                <div className="max-w-lg mx-auto relative group">
                    <div className="absolute inset-y-0 left-4 flex items-center pointer-events-none">
                        <Search className="h-5 w-5 text-gray-400 group-focus-within:text-brand transition-colors" />
                    </div>
                    <input
                        type="search"
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                        placeholder={`Busque por "${products[0]?.name || 'Smash Chicken'}"...`}
                        className="w-full bg-gray-100 dark:bg-gray-900 border-none h-14 pl-12 pr-4 rounded-xl text-sm font-medium focus:ring-2 focus:ring-brand/20 transition-all shadow-sm"
                    />
                </div>
            </div>

            {
                !isStoreOpen && (
                    <div className="bg-amber-50 dark:bg-amber-950/20 border-b border-amber-100 dark:border-amber-900/50 px-5 py-4 flex items-center gap-4 animate-in slide-in-from-top duration-500">
                        <div className="h-10 w-10 rounded-xl bg-amber-100 dark:bg-amber-900 text-amber-600 dark:text-amber-400 flex items-center justify-center shrink-0 shadow-lg shadow-amber-500/10">
                            <Info className="h-5 w-5" />
                        </div>
                        <div>
                            <h3 className="font-black text-amber-900 dark:text-amber-100 uppercase tracking-tighter italic text-xs">Loja Fechada no momento</h3>
                            <p className="text-amber-700 dark:text-amber-400 text-[10px] font-bold leading-tight uppercase tracking-tighter">Já encerramos por hoje, mas sinta-se à vontade para navegar!</p>
                        </div>
                    </div>
                )
            }

            {isStoreOpen && storeSettings && (
                <div className="mb-1" />
            )}

            {
                !searchQuery && categories.length > 0 && (
                    <StickyCategoryBar
                        categories={categories}
                        activeCategoryId={activeCategory}
                        onSelect={handleSelectCategory}
                    />
                )
            }

            <div className="px-5 py-8 space-y-14">
                {/* Herói / Sugestão do Chef (Fase 4) */}
                {!searchQuery && products.length > 0 && (
                    <div className="relative overflow-hidden rounded-xl bg-black h-48 flex items-center group cursor-pointer shadow-2xl shadow-brand/10 transition-transform active:scale-95"
                        onClick={() => setSelectedProduct(products[0])}>
                        <div className="absolute inset-0 opacity-60">
                            {products[0].image_url ? (
                                <Image
                                    src={products[0].image_url}
                                    alt="Destaque"
                                    fill
                                    className="object-cover group-hover:scale-110 transition-transform duration-700"
                                />
                            ) : (
                                <div className="bg-gradient-to-br from-brand to-red-900 h-full w-full" />
                            )}
                        </div>
                        <div className="absolute inset-0 bg-gradient-to-t from-black via-transparent to-transparent opacity-80" />

                        <div className="relative z-10 px-6 space-y-2">
                            <span className="inline-flex items-center gap-1.5 px-3 py-1.5 bg-white/10 backdrop-blur-md border border-white/20 text-white text-[10px] font-black uppercase tracking-widest rounded-full shadow-lg">
                                <div className="h-1.5 w-1.5 rounded-full bg-brand animate-pulse" />
                                Sugestão do Chef
                            </span>
                            <div>
                                <h3 className="text-xl font-black text-white uppercase italic tracking-tighter leading-none">{products[0].name}</h3>
                                <p className="text-[10px] text-gray-300 font-bold uppercase tracking-widest mt-1">Experimente o nosso sabor mais exclusivo</p>
                            </div>
                            <div className="flex items-center gap-2 pt-2">
                                <span className="text-lg font-black text-white italic tracking-tighter">
                                    {new Intl.NumberFormat("pt-BR", { style: "currency", currency: "BRL" }).format(products[0].price)}
                                </span>
                                <div className="h-8 w-8 rounded-full bg-white flex items-center justify-center text-brand">
                                    <Plus className="h-5 w-5" />
                                </div>
                            </div>
                        </div>
                    </div>
                )}

                {/* Seção Mais Pedidos */}
                {!searchQuery && products.length > 0 && (
                    <div className="space-y-6">
                        <div className="px-1">
                            <h2 className="text-xl font-bold text-color-primary tracking-tight">Destaques</h2>
                        </div>

                        <div className="grid grid-cols-3 gap-x-4 gap-y-8 px-1">
                            {products.slice(0, 6).map((product) => (
                                <ProductCard
                                    key={`top-${product.id}`}
                                    product={product}
                                    onAdd={(p) => isStoreOpen && setSelectedProduct(p)}
                                    isStoreOpen={isStoreOpen}
                                    isFeatured={true}
                                />
                            ))}
                        </div>
                    </div>
                )}

                {filteredCategoriesBySearch.map((category) => {
                    const catProducts = filteredProductsBySearch.filter(
                        (p) => p.category_id === category.id
                    );

                    return (
                        <div key={category.id} id={`section-${category.id}`} className="scroll-mt-28">
                            <div className="flex items-center justify-between mb-5">
                                {/* Título da categoria — text-display (20px/600) + text-primary */}
                                <h2 className="text-display font-bold text-color-primary">
                                    {category.name}
                                </h2>
                                {/* Contagem — text-label (12px) + text-tertiary */}
                                <span className="text-label-sm text-color-tertiary bg-gray-100 dark:bg-gray-800 px-3 py-1 rounded-full font-bold">
                                    {catProducts.length} itens
                                </span>
                            </div>
                            <div className="grid gap-5 sm:grid-cols-2 lg:grid-cols-3">
                                {catProducts.length > 0 ? (
                                    catProducts.map((product) => (
                                        <ProductCard
                                            key={product.id}
                                            product={product}
                                            onAdd={(p) => isStoreOpen && setSelectedProduct(p)}
                                            isStoreOpen={isStoreOpen}
                                        />
                                    ))
                                ) : (
                                    <div className="col-span-full py-8 text-center bg-gray-50 dark:bg-gray-900/50 rounded-xl border border-dashed border-gray-200 dark:border-gray-800">
                                        <p className="text-gray-400 text-sm">Nenhum produto disponível nesta categoria ainda.</p>
                                    </div>
                                )}
                            </div>
                        </div>
                    );
                })}

                {filteredProductsBySearch.length === 0 && (
                    <div className="flex flex-col items-center justify-center py-24 text-center">
                        <div className="bg-gray-100 dark:bg-gray-800 p-5 rounded-full mb-4">
                            <Search className="h-10 w-10 text-gray-300" />
                        </div>
                        {/* Sem resultados — text-title + text-primary */}
                        <h3 className="text-title font-bold text-color-primary">Nada encontrado</h3>
                        {/* Descrição — text-body + text-secondary */}
                        <p className="text-body-content max-w-xs mt-2">
                            Não encontramos nenhum item chamado "{searchQuery}". Tente outro nome ou navegue pelas categorias.
                        </p>
                    </div>
                )}
            </div>

            <ProductDrawer
                product={selectedProduct}
                onClose={() => setSelectedProduct(null)}
                isStoreOpen={isStoreOpen}
            />
            <div className="h-20" />
        </div >
    );
}

﻿"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { useCartStore } from "@/store/cartStore";
import { Button } from "@/components/core/Button";
import { motion, AnimatePresence } from "framer-motion";
import { Input, Label } from "@/components/core/Input";
import { Card, CardHeader, CardTitle, CardContent } from "@/components/core/Card";
import { login, signup } from "@/lib/actions/authActions";
import { createOrder } from "@/lib/actions/orderActions";
import { ArrowLeft, MapPin, Navigation, ShoppingBag, CreditCard, Banknote, QrCode, Clock, Info, User, Smartphone, Mail, Lock, Wallet, CheckCircle2, ShoppingCart, ChevronDown, ChevronUp, Plus, AlertTriangle, Loader2, ExternalLink } from "lucide-react";
import { StoreConfig } from "@/lib/actions/adminSettingsActions";
import { cn } from "@/lib/utils";
import { toast } from "sonner";
import { calculateDeliveryRemote } from "@/modules/delivery/delivery.client";
import { DeliveryCalculationResult } from "@/modules/delivery/delivery.types";
import { usePushNotifications } from "@/hooks/usePushNotifications";

const fmt = (v: number) =>
    new Intl.NumberFormat("pt-BR", { style: "currency", currency: "BRL" }).format(v);

interface CheckoutViewProps {
    user: any;
    profile: any;
    savedAddresses?: any[];
    storeSettings?: StoreConfig | null;
    isStoreOpen?: boolean;
}

export function CheckoutView({ user, profile, savedAddresses = [], storeSettings, isStoreOpen = true }: CheckoutViewProps) {
    const router = useRouter();
    const { items, totalPrice, totalItems, clearCart } = useCartStore();
    const { requestPermissionAndSubscribe } = usePushNotifications();

    const [loading, setLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [authMode, setAuthMode] = useState<"LOGIN" | "SIGNUP">("LOGIN");
    const [deliveryMethod, setDeliveryMethod] = useState<"ON_DELIVERY" | "ON_PICKUP">("ON_DELIVERY");
    const [paymentMethod, setPaymentMethod] = useState<"DINHEIRO" | "CREDITO" | "DEBITO" | "PIX">("DINHEIRO");
    const [changeFor, setChangeFor] = useState<string>("");
    const [showSuccess, setShowSuccess] = useState(false);
    const [orderId, setOrderId] = useState<string | null>(null);
    const [isSummaryExpanded, setIsSummaryExpanded] = useState(true);
    const [isOutsideArea, setIsOutsideArea] = useState(false);
    const [isCheckingArea, setIsCheckingArea] = useState(false);
    const [deliveryResult, setDeliveryResult] = useState<DeliveryCalculationResult | null>(null);
    const [isAddressDropdownOpen, setIsAddressDropdownOpen] = useState(false);
    const [showClearCartModal, setShowClearCartModal] = useState(false);

    const { addItem } = useCartStore(); // Para o upsell

    // Pega o endereço padrão se existir, senão o primeiro, senão vazio
    const defaultAddr = savedAddresses.find(a => a.is_default) || savedAddresses[0];
    const initialAddressString = defaultAddr
        ? `${defaultAddr.street}, ${defaultAddr.number}${defaultAddr.complement ? ' - ' + defaultAddr.complement : ''}. ${defaultAddr.neighborhood}, ${defaultAddr.city}`
        : "";

    const [selectedAddressObj, setSelectedAddressObj] = useState<any>(defaultAddr);
    const [address, setAddress] = useState(initialAddressString);

    // Validação de Ã rea de Entrega (Simulada para demonstração conforme pedido)
    // Validação de Área de Entrega Real com o Motor de Delivery
    useEffect(() => {
        async function checkDelivery() {
            if (deliveryMethod === "ON_DELIVERY" && selectedAddressObj) {
                setIsCheckingArea(true);
                setError(null);

                try {
                    const lat = selectedAddressObj.lat || 0;
                    const lng = selectedAddressObj.lng || 0;

                    const result = await calculateDeliveryRemote({
                        lat,
                        lng,
                        orderValue: totalPrice()
                    });

                    setDeliveryResult(result);
                    setIsOutsideArea(false); // Sempre false na lógica fixa
                    setError(null);
                } catch (err) {
                    console.error("Erro ao validar entrega:", err);
                    setError("Erro ao calcular taxa de entrega.");
                } finally {
                    setIsCheckingArea(false);
                }
            } else {
                setIsOutsideArea(false);
                setIsCheckingArea(false);
                setDeliveryResult(null);
            }
        }

        checkDelivery();
    }, [selectedAddressObj, deliveryMethod, totalPrice]);

    const handleLogin = async (e: React.FormEvent<HTMLFormElement>) => {
        e.preventDefault();
        setLoading(true);
        setError(null);
        const formData = new FormData(e.currentTarget);
        const res = await login(formData);
        if ((res as any).error) {
            setError((res as any).error);
        } else {
            // Roteamento Inteligente:
            if ((res as any).isAdmin) {
                router.push("/admin");
            } else if (items.length === 0) {
                // Se o carrinho estiver vazio, muito provavelmente o usuário clicou no menu "Perfil"
                router.push("/profile");
            } else {
                // Caso contrário (fazendo pedido), mantém na mesma tela
                window.location.reload();
            }
        }
        setLoading(false);
    };

    const handleSignup = async (e: React.FormEvent<HTMLFormElement>) => {
        e.preventDefault();
        setLoading(true);
        setError(null);
        const formData = new FormData(e.currentTarget);
        const res = await signup(formData);
        if ((res as any).error) {
            setError((res as any).error);
        } else {
            if (items.length === 0) {
                router.push("/profile");
            } else {
                window.location.reload();
            }
        }
        setLoading(false);
    };

    const handleCreateOrder = async (e: React.FormEvent<HTMLFormElement>) => {
        e.preventDefault();
        setLoading(true);
        setError(null);

        const subtotal = totalPrice();
        const deliveryFee = deliveryMethod === "ON_DELIVERY" ? (deliveryResult?.taxaEntrega || 0) : 0;
        const total = subtotal + deliveryFee;

        const data = {
            items,
            totalAmount: total,
            deliveryAddress: deliveryMethod === "ON_PICKUP" ? "RETIRADA NA LOJA" : address,
            customerName: profile?.name || user?.user_metadata?.name || "Cliente",
            customerPhone: profile?.phone || user?.user_metadata?.phone || "000000000",
            paymentMethod: paymentMethod,
            deliveryMethod: deliveryMethod,
            changeFor: paymentMethod === "DINHEIRO" ? Number(changeFor) || null : null,
        };

        if (!isStoreOpen) {
            setError("O estabelecimento fechou. Não é possível concluir o pedido.");
            setLoading(false);
            return;
        }

        const res = await createOrder(data as any);

        if (res.error) {
            setError(res.error);
            setLoading(false);
        } else {
            clearCart();
            setOrderId(res.orderId);
            setShowSuccess(true);
            setLoading(false);
        }
    };

    // -------- AUTH FORM --------
    const renderAuthForm = () => (
        <div className="flex flex-col min-h-screen bg-gray-50/50 dark:bg-black w-full pb-10">
            {/* Header / Nav */}
            <header className="sticky top-0 z-40 bg-white/80 dark:bg-black/80 backdrop-blur-xl border-b border-gray-100 dark:border-white/5 px-4 pt-[calc(env(safe-area-inset-top,0px)+16px)] pb-4 flex items-center justify-between shadow-sm">
                <button
                    onClick={() => router.back()}
                    className="flex h-10 w-10 items-center justify-center rounded-full bg-gray-100/80 dark:bg-white/10 hover:bg-gray-200 dark:hover:bg-white/20 transition-colors active:scale-95"
                >
                    <ArrowLeft className="h-5 w-5 text-foreground" />
                </button>
                <div className="text-xs font-black uppercase tracking-widest text-[#9E9E9E]">
                    Acesso Seguro
                </div>
                <div className="w-10" /> {/* spacer */}
            </header>

            <motion.div
                initial={{ opacity: 0, y: 15 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ type: "spring", stiffness: 350, damping: 25 }}
                className="mx-auto w-full max-w-md px-5 pt-8"
            >
                <div className="mb-8">
                    <h1 className="text-[28px] font-black tracking-tight text-foreground leading-tight mb-2">
                        {authMode === "LOGIN" ? "Que bom te ver\npor aqui!" : "Crie sua conta"}
                    </h1>
                    <p className="text-[14px] text-gray-700 dark:text-gray-300 font-medium">
                        {authMode === "LOGIN"
                            ? "Entre para confirmar o seu pedido rapidinho."
                            : "Preencha seus dados para acompanhar seus pedidos."}
                    </p>
                </div>

                <div className="bg-white dark:bg-[#111] p-6 rounded-3xl shadow-[0_8px_30px_rgba(0,0,0,0.06)] dark:shadow-none border border-gray-100 dark:border-white/5">
                    <form
                        key={authMode}
                        onSubmit={authMode === "LOGIN" ? handleLogin : handleSignup}
                        className="space-y-5"
                        autoComplete="off"
                    >
                        <AnimatePresence mode="popLayout">
                            {authMode === "SIGNUP" && (
                                <motion.div
                                    initial={{ opacity: 0, height: 0 }}
                                    animate={{ opacity: 1, height: "auto" }}
                                    exit={{ opacity: 0, height: 0 }}
                                    className="space-y-5"
                                >
                                    <div className="space-y-1.5">
                                        <Label htmlFor="name">Nome completo</Label>
                                        <Input
                                            id="name"
                                            name="name"
                                            required
                                            placeholder="João Silva"
                                            leftIcon={<User className="h-5 w-5" />}
                                            className="bg-gray-50 dark:bg-white/5 border border-transparent focus:border-brand/20 transition-all font-medium text-base shadow-none"
                                        />
                                    </div>
                                    <div className="space-y-1.5">
                                        <Label htmlFor="phone">Celular (com DDD)</Label>
                                        <Input
                                            id="phone"
                                            name="phone"
                                            type="tel"
                                            required
                                            placeholder="(11) 90000-0000"
                                            leftIcon={<Smartphone className="h-5 w-5" />}
                                            className="bg-gray-50 dark:bg-white/5 border border-transparent focus:border-brand/20 transition-all font-medium text-base shadow-none"
                                        />
                                    </div>
                                </motion.div>
                            )}
                        </AnimatePresence>

                        <div className="space-y-1.5 focus-within:relative z-10">
                            <Label htmlFor="email">E-mail</Label>
                            <Input
                                id="email"
                                name="email"
                                type="email"
                                required
                                placeholder="exemplo@email.com"
                                leftIcon={<Mail className="h-5 w-5" />}
                                className="bg-gray-50 dark:bg-white/5 border border-transparent focus:border-brand/20 transition-all font-medium text-base shadow-none"
                            />
                        </div>

                        <div className="space-y-1.5 focus-within:relative z-10">
                            <Label htmlFor="password">Senha</Label>
                            <Input
                                id="password"
                                name="password"
                                type="password"
                                required
                                placeholder="••••••••"
                                leftIcon={<Lock className="h-5 w-5" />}
                                autoComplete={authMode === "SIGNUP" ? "new-password" : "current-password"}
                                className="bg-gray-50 dark:bg-white/5 border border-transparent focus:border-brand/20 transition-all font-medium text-base shadow-none"
                            />
                        </div>

                        {error && (
                            <motion.div initial={{ opacity: 0, y: -5 }} animate={{ opacity: 1, y: 0 }} className="pt-1">
                                <p className="text-xs font-bold text-red-500 bg-red-50 dark:bg-red-500/10 p-3 rounded-xl border border-red-100 dark:border-red-500/20 flex items-center gap-2">
                                    <AlertTriangle className="h-4 w-4" />
                                    {error}
                                </p>
                            </motion.div>
                        )}

                        <div className="pt-2">
                            <Button
                                type="submit"
                                className="w-full h-14 rounded-2xl text-[15px] font-bold shadow-xl shadow-brand/20 active:scale-[0.98] transition-all"
                                disabled={loading}
                            >
                                {loading ? (
                                    <span className="flex items-center gap-2"><Loader2 className="h-5 w-5 animate-spin" /> Processando...</span>
                                ) : (
                                    authMode === "LOGIN" ? "Continuar" : "Criar Conta"
                                )}
                            </Button>
                        </div>

                        <div className="text-center pt-3 border-t border-gray-100 dark:border-white/5 mt-6">
                            <button
                                type="button"
                                onClick={() => setAuthMode(authMode === "LOGIN" ? "SIGNUP" : "LOGIN")}
                                className="text-sm font-bold text-gray-700 dark:text-gray-300 hover:text-foreground transition-colors p-2"
                            >
                                {authMode === "LOGIN" ? "Ainda não tem conta? " : "Já possui conta? "}
                                <span className="text-foreground underline decoration-gray-400 dark:decoration-gray-600 underline-offset-4 font-black">
                                    {authMode === "LOGIN" ? "Cadastre-se" : "Faça login"}
                                </span>
                            </button>
                        </div>
                    </form>
                </div>
            </motion.div>
        </div>
    );

    const selectSavedAddress = (addr: any) => {
        const addrStr = `${addr.street}, ${addr.number}${addr.complement ? ' - ' + addr.complement : ''}. ${addr.neighborhood}, ${addr.city}`;
        setAddress(addrStr);
    };

    // -------- CHECKOUT FORM (authenticated) --------
    const renderOrderForm = () => {
        if (items.length === 0) {
            return (
                <div className="flex h-screen flex-col items-center justify-center p-6 text-center">
                    <div className="flex h-20 w-20 items-center justify-center rounded-full bg-gray-100 dark:bg-gray-800 mb-6">
                        <ShoppingBag className="h-10 w-10 text-gray-400" />
                    </div>
                    <h2 className="text-xl font-bold text-foreground">Sua sacola está vazia</h2>
                    <p className="mt-2 text-sm text-gray-500">Adicione itens antes de finalizar.</p>
                    <Button className="mt-6" onClick={() => router.push("/")}>
                        Voltar ao Cardápio
                    </Button>
                </div>
            );
        }

        const subtotal = totalPrice();
        const count = totalItems();
        const deliveryFee = deliveryMethod === "ON_DELIVERY" ? (deliveryResult?.taxaEntrega || 0) : 0;
        const total = subtotal + deliveryFee;

        return (
            <div className="w-full bg-gray-50 dark:bg-background min-h-screen pb-40">
                {/* Header Padronizado e Full Width */}
                <header className="sticky top-0 z-40 bg-surface shadow-sm border-b border-gray-100 dark:border-gray-800">
                    <div className="mx-auto w-full max-w-lg px-4 pt-[calc(env(safe-area-inset-top,0px)+16px)] pb-4 flex items-center justify-between">
                        <div className="flex items-center gap-3">
                            <motion.button
                                whileHover={{ scale: 1.05 }}
                                whileTap={{ scale: 0.9 }}
                                onClick={() => router.push("/cart")}
                                className="flex h-10 w-10 items-center justify-center rounded-full bg-gray-50 dark:bg-gray-900 border border-gray-100 dark:border-gray-800 hover:bg-gray-100 dark:hover:bg-gray-800 transition-all shadow-sm"
                            >
                                <ArrowLeft className="h-5 w-5 text-foreground" />
                            </motion.button>
                            <h1 className="text-lg font-bold text-foreground">Finalizar Pedido</h1>
                        </div>

                        <button
                            type="button"
                            onClick={() => setShowClearCartModal(true)}
                            className="text-[10px] font-black uppercase text-red-500 tracking-widest hover:bg-red-50 dark:hover:bg-red-950/20 px-3 py-2 rounded-lg transition-colors"
                        >
                            Limpar
                        </button>
                    </div>
                </header>

                <form onSubmit={handleCreateOrder} className="mx-auto w-full max-w-lg space-y-6 px-4 mt-6">
                    {/* Resumo do pedido Accordion */}
                    <div className="rounded-xl bg-surface shadow-[0_8px_30px_rgb(0,0,0,0.04)] border border-gray-100 dark:border-gray-800 overflow-hidden">
                        <button
                            type="button"
                            onClick={() => setIsSummaryExpanded(!isSummaryExpanded)}
                            className="w-full p-5 flex items-center justify-between hover:bg-gray-50 dark:hover:bg-gray-900/50 transition-colors"
                        >
                            <div className="flex items-center gap-3">
                                <div className="h-10 w-10 rounded-xl bg-brand/5 flex items-center justify-center text-brand">
                                    <ShoppingBag className="h-5 w-5" />
                                </div>
                                <div className="text-left">
                                    <h2 className="text-sm font-black uppercase italic tracking-tighter text-foreground">Resumo do pedido</h2>
                                    <p className="text-[10px] font-bold text-gray-500 dark:text-gray-400 uppercase">{count} {count === 1 ? 'item' : 'itens'}</p>
                                </div>
                            </div>
                            <div className="flex items-center gap-3">
                                <span className="text-lg font-black text-foreground tracking-tighter">{fmt(total)}</span>
                                {isSummaryExpanded ? <ChevronUp className="h-4 w-4 text-gray-400" /> : <ChevronDown className="h-4 w-4 text-gray-400" />}
                            </div>
                        </button>

                        <AnimatePresence>
                            {isSummaryExpanded && (
                                <motion.div
                                    initial={{ height: 0, opacity: 0 }}
                                    animate={{ height: "auto", opacity: 1 }}
                                    exit={{ height: 0, opacity: 0 }}
                                    className="overflow-hidden border-t border-gray-50 dark:border-gray-800/50 bg-gray-50/30 dark:bg-black/10"
                                >
                                    <div className="p-5 space-y-3">
                                        {items.map((item) => {
                                            const extrasTotal = item.extras?.reduce((acc, curr) => acc + curr.price, 0) || 0;
                                            return (
                                                <div key={item.id} className="flex justify-between text-sm items-center">
                                                    <div className="flex flex-col">
                                                        <span className="text-gray-800 dark:text-gray-200 font-bold text-xs">
                                                            {item.quantity}x {item.product.name}
                                                        </span>
                                                        {item.extras.length > 0 && (
                                                            <span className="text-[10px] text-gray-500 font-bold uppercase italic">
                                                                + {item.extras.map(e => e.name).join(', ')}
                                                            </span>
                                                        )}
                                                    </div>
                                                    <span className="font-black text-xs text-gray-800 dark:text-gray-200 tracking-tight">{fmt((item.product.price + extrasTotal) * item.quantity)}</span>
                                                </div>
                                            );
                                        })}

                                        <div className="mt-4 pt-4 border-t border-gray-100 dark:border-gray-800 space-y-2">
                                            <div className="flex justify-between text-[11px] font-bold uppercase tracking-wider">
                                                <span className="text-gray-800 dark:text-gray-200">Subtotal</span>
                                                <span className="text-gray-800 dark:text-gray-200">{fmt(subtotal)}</span>
                                            </div>
                                            {deliveryMethod === "ON_DELIVERY" && (
                                                <div className="flex justify-between text-[11px] font-bold uppercase tracking-wider">
                                                    <span className="text-gray-800 dark:text-gray-200">Taxa de entrega</span>
                                                    <span className={isCheckingArea || deliveryFee === 0 ? "text-emerald-500" : "text-gray-800 dark:text-gray-200"}>
                                                        {isCheckingArea
                                                            ? "..."
                                                            : deliveryFee > 0
                                                                ? fmt(deliveryFee)
                                                                : "Grátis"}
                                                    </span>
                                                </div>
                                            )}
                                            <div className="flex justify-between text-[13px] font-black uppercase tracking-wider mt-2 pt-3 border-t border-gray-100 dark:border-gray-800">
                                                <span className="text-gray-800 dark:text-gray-200">Total</span>
                                                <span className="text-gray-800 dark:text-gray-200">{fmt(total)}</span>
                                            </div>
                                        </div>
                                    </div>
                                </motion.div>
                            )}
                        </AnimatePresence>
                    </div>

                    {/* Método de entrega */}
                    <div className="space-y-3">
                        <h2 className="font-bold text-foreground">Como deseja receber?</h2>
                        <div className="grid grid-cols-2 gap-3">
                            <button
                                type="button"
                                onClick={() => setDeliveryMethod("ON_DELIVERY")}
                                className={cn(
                                    "p-4 rounded-xl border-2 flex flex-col items-center gap-2 transition-all active:scale-95",
                                    deliveryMethod === "ON_DELIVERY"
                                        ? "border-brand bg-brand/5 text-foreground shadow-sm"
                                        : "border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-900 text-gray-600 dark:text-gray-400 hover:border-gray-300"
                                )}
                            >
                                <div className={cn("h-10 w-10 rounded-lg flex items-center justify-center transition-colors shadow-sm",
                                    deliveryMethod === "ON_DELIVERY" ? "bg-brand/10 text-brand" : "bg-gray-100 dark:bg-gray-800 text-gray-500 dark:text-gray-400")}>
                                    <MapPin className={cn("h-5 w-5", deliveryMethod === "ON_DELIVERY" && "stroke-[2.5px]")} />
                                </div>
                                <span className="text-[10px] font-black uppercase tracking-widest italic">Entrega</span>
                            </button>

                            <button
                                type="button"
                                onClick={() => setDeliveryMethod("ON_PICKUP")}
                                className={cn(
                                    "p-4 rounded-xl border-2 flex flex-col items-center gap-2 transition-all active:scale-95",
                                    deliveryMethod === "ON_PICKUP"
                                        ? "border-brand bg-brand/5 text-foreground shadow-sm"
                                        : "border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-900 text-gray-600 dark:text-gray-400 hover:border-gray-300"
                                )}
                            >
                                <div className={cn("h-10 w-10 rounded-lg flex items-center justify-center transition-colors shadow-sm",
                                    deliveryMethod === "ON_PICKUP" ? "bg-brand/10 text-brand" : "bg-gray-100 dark:bg-gray-800 text-gray-500 dark:text-gray-400")}>
                                    <Navigation className={cn("h-5 w-5", deliveryMethod === "ON_PICKUP" && "stroke-[2.5px]")} />
                                </div>
                                <span className="text-[10px] font-black uppercase tracking-widest italic">Retirada</span>
                            </button>
                        </div>
                    </div>

                    {deliveryMethod === "ON_DELIVERY" && (
                        <div className="space-y-3 animate-in fade-in slide-in-from-top-4">
                            <div className="flex items-center justify-between">
                                <h2 className="font-bold text-foreground">Endereço de Entrega</h2>
                                <button
                                    type="button"
                                    onClick={() => router.push("/profile/addresses")}
                                    className="text-[10px] font-bold uppercase text-brand tracking-widest hover:brightness-110"
                                >
                                    {address ? "Alterar" : "Cadastrar"}
                                </button>
                            </div>

                            <div className="relative">
                                {address ? (
                                    <div
                                        className="p-5 rounded-xl bg-surface border border-gray-100 dark:border-gray-800 shadow-sm flex items-start gap-4 hover:border-brand/20 transition-colors group cursor-pointer"
                                        onClick={() => savedAddresses.length > 1 ? setIsAddressDropdownOpen(!isAddressDropdownOpen) : router.push("/profile/addresses")}
                                    >
                                        <div className="h-10 w-10 min-w-[40px] rounded-xl bg-brand/5 flex items-center justify-center text-brand">
                                            <MapPin className="h-5 w-5" />
                                        </div>
                                        <div className="flex-1 min-w-0">
                                            <p className="text-sm font-bold text-foreground leading-tight line-clamp-1">{address.split('.')[0]}</p>
                                            <p className="text-[10px] font-black uppercase text-gray-400 mt-1 tracking-tight truncate">
                                                {address.includes('.') ? address.split('.')[1] : ""}
                                            </p>
                                        </div>
                                        {savedAddresses.length > 1 && (
                                            <ChevronDown className={cn("h-4 w-4 text-gray-300 mt-3 group-hover:text-brand transition-transform", isAddressDropdownOpen && "rotate-180")} />
                                        )}
                                    </div>
                                ) : (
                                    <button
                                        type="button"
                                        onClick={() => router.push("/profile/addresses")}
                                        className="w-full p-8 rounded-xl border-2 border-dashed border-gray-200 dark:border-gray-800 bg-gray-50/50 dark:bg-gray-900/30 flex flex-col items-center gap-3 text-center transition-all hover:bg-gray-50 dark:hover:bg-gray-900/50"
                                    >
                                        <div className="h-12 w-12 rounded-full bg-brand/10 flex items-center justify-center text-brand mb-1">
                                            <Plus className="h-6 w-6" />
                                        </div>
                                        <p className="text-xs font-bold text-gray-500">Nenhum endereço selecionado.<br />Cadastre um agora para prosseguir.</p>
                                    </button>
                                )}

                                <AnimatePresence>
                                    {isAddressDropdownOpen && (
                                        <motion.div
                                            initial={{ opacity: 0, y: -10 }}
                                            animate={{ opacity: 1, y: 0 }}
                                            exit={{ opacity: 0, y: -10 }}
                                            className="absolute top-full left-0 right-0 mt-2 z-50 bg-surface border border-gray-100 dark:border-gray-800 rounded-xl shadow-2xl overflow-hidden"
                                        >
                                            <div className="max-h-60 overflow-y-auto">
                                                {savedAddresses.map((addr: any) => (
                                                    <div
                                                        key={addr.id}
                                                        onClick={() => {
                                                            const addrStr = `${addr.street}, ${addr.number}${addr.complement ? ' - ' + addr.complement : ''}. ${addr.neighborhood}, ${addr.city}`;
                                                            setAddress(addrStr);
                                                            setSelectedAddressObj(addr);
                                                            setIsAddressDropdownOpen(false);
                                                        }}
                                                        className={cn(
                                                            "p-4 border-b border-gray-50 dark:border-gray-800 last:border-0 hover:bg-gray-50 dark:hover:bg-gray-900 cursor-pointer flex items-center gap-3 transition-colors",
                                                            selectedAddressObj?.id === addr.id && "bg-brand/5"
                                                        )}
                                                    >
                                                        <MapPin className={cn("h-4 w-4 shrink-0", selectedAddressObj?.id === addr.id ? "text-brand" : "text-gray-400")} />
                                                        <div className="min-w-0">
                                                            <p className={cn("text-xs font-bold truncate", selectedAddressObj?.id === addr.id ? "text-foreground" : "text-gray-600")}>
                                                                {addr.street}, {addr.number}
                                                            </p>
                                                            <p className="text-[10px] text-gray-400 uppercase font-bold truncate">
                                                                {addr.neighborhood}
                                                            </p>
                                                        </div>
                                                    </div>
                                                ))}
                                                <button
                                                    onClick={() => router.push("/profile/addresses")}
                                                    className="w-full p-4 text-center text-[10px] font-black uppercase text-brand tracking-widest hover:bg-brand/5 border-t border-gray-50 dark:border-gray-800"
                                                >
                                                    Gerenciar endereços
                                                </button>
                                            </div>
                                        </motion.div>
                                    )}
                                </AnimatePresence>
                            </div>

                            {/* Alerta de Endereço Validado */}
                            {deliveryMethod === "ON_DELIVERY" && address && (
                                <motion.div
                                    initial={{ opacity: 0, scale: 0.95 }}
                                    animate={{ opacity: 1, scale: 1 }}
                                    className={cn(
                                        "p-4 rounded-xl border flex gap-3 transition-colors",
                                        isCheckingArea ? "bg-gray-50 dark:bg-gray-900 border-gray-100 dark:border-gray-800" :
                                            "bg-emerald-50 dark:bg-emerald-950/20 border-emerald-100 dark:border-emerald-900/30"
                                    )}
                                >
                                    {isCheckingArea ? (
                                        <Loader2 className="h-5 w-5 text-gray-400 animate-spin shrink-0" />
                                    ) : (
                                        <CheckCircle2 className="h-5 w-5 text-emerald-500 shrink-0" />
                                    )}
                                    <div className="space-y-1">
                                        <p className={cn(
                                            "text-[10px] font-black uppercase tracking-wider leading-none mt-1",
                                            isCheckingArea ? "text-gray-400" : "text-emerald-600"
                                        )}>
                                            {isCheckingArea ? "Buscando taxa..." : "Endereço verificado"}
                                        </p>
                                        <p className="text-[10px] font-bold text-gray-500 dark:text-gray-400 tracking-tight leading-tight">
                                            {isCheckingArea ? "Consultando serviços de entrega..." :
                                                `Taxa de entrega computada. Tempo estimado de ${deliveryResult?.tempoEstimadoMin} minutos.`}
                                        </p>
                                    </div>
                                </motion.div>
                            )}

                            {deliveryResult?.pedidoMinimo && totalPrice() < deliveryResult.pedidoMinimo && (
                                <div className="p-3 bg-amber-50 dark:bg-amber-950/20 border border-amber-100 dark:border-amber-900/30 rounded-xl flex items-center gap-2">
                                    <AlertTriangle className="h-4 w-4 text-amber-500" />
                                    <p className="text-[10px] font-bold text-amber-700 dark:text-amber-400 uppercase tracking-tighter">
                                        Pedido mín. para sua região: {fmt(deliveryResult.pedidoMinimo)} (Faltam {fmt(deliveryResult.pedidoMinimo - totalPrice())})
                                    </p>
                                </div>
                            )}

                            {/* Hidden Input for Form Submission if needed, but we handle in handleCreateOrder */}
                            <input type="hidden" name="address" value={address} required />
                        </div>
                    )}

                    {deliveryMethod === "ON_PICKUP" && (
                        <div className="space-y-4 animate-in fade-in slide-in-from-top-4">
                            <div className="p-6 rounded-2xl bg-white dark:bg-gray-900 border border-gray-100 dark:border-gray-800 shadow-sm space-y-5">
                                <h3 className="text-center font-black uppercase italic tracking-tighter text-foreground text-sm">Onde Estamos</h3>

                                <div className="flex items-center justify-center gap-2 px-4 text-center">
                                    <MapPin className="h-3 w-3 text-red-500 shrink-0" />
                                    <p className="text-[11px] font-bold text-gray-600 dark:text-gray-400 leading-tight">
                                        {storeSettings?.pickup_address || "Endereço não cadastrado"}
                                    </p>
                                </div>

                                {/* Mini Mapa Placeholder Estilo Premium */}
                                <div className="relative w-full h-44 rounded-2xl bg-gray-50 dark:bg-black/20 overflow-hidden border border-gray-100 dark:border-gray-800 group">
                                    {/* Grid Pattern */}
                                    <div
                                        className="absolute inset-0 opacity-[0.4]"
                                        style={{
                                            backgroundImage: 'linear-gradient(#e5e7eb 1px, transparent 1px), linear-gradient(90deg, #e5e7eb 1px, transparent 1px)',
                                            backgroundSize: '24px 24px'
                                        }}
                                    />

                                    {/* Pin Centralizado */}
                                    <div className="absolute inset-0 flex items-center justify-center">
                                        <div className="relative">
                                            <div className="absolute inset-0 bg-black/10 blur-xl rounded-full scale-150" />
                                            <div className="relative h-12 w-12 rounded-full bg-white dark:bg-gray-800 flex items-center justify-center shadow-xl border border-gray-100 dark:border-gray-800">
                                                <MapPin className="h-6 w-6 text-gray-900 dark:text-gray-100 fill-current" />
                                            </div>
                                        </div>
                                    </div>

                                    {/* BotÃ£o Flutuante Estilo ReferÃªncia */}
                                    <div className="absolute bottom-5 left-5 right-5">
                                        <a
                                            href={`https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(storeSettings?.pickup_address || '')}`}
                                            target="_blank"
                                            rel="noopener noreferrer"
                                            className="flex items-center justify-center gap-2 w-full h-12 rounded-xl bg-white dark:bg-gray-900 shadow-lg border border-gray-100 dark:border-gray-800 text-foreground text-[11px] font-black uppercase italic tracking-widest hover:scale-[1.02] transition-all"
                                        >
                                            Ver no Google Maps
                                            <ExternalLink className="h-3 w-3 opacity-50" />
                                        </a>
                                    </div>
                                </div>
                            </div>

                            <div className="p-3 rounded-xl bg-gray-50 dark:bg-gray-900/50 flex items-center gap-3 border border-gray-100 dark:border-gray-800">
                                <Info className="h-4 w-4 text-brand" />
                                <p className="text-[10px] text-gray-500 font-bold uppercase tracking-tight">O seu pedido estará disponível em aproximadamente <span className="text-foreground">{storeSettings?.pickup_estimated_time || '15-20 min'}</span>.</p>
                            </div>
                        </div>
                    )}

                    <div className="space-y-4">
                        <h2 className="font-bold text-foreground">Forma de Pagamento</h2>
                        <div className="grid grid-cols-4 gap-2">
                            {/* CREDITO */}
                            <button
                                type="button"
                                onClick={() => setPaymentMethod("CREDITO")}
                                className={cn(
                                    "py-3 px-1 rounded-xl border-2 flex flex-col items-center justify-center gap-2 transition-all active:scale-95",
                                    paymentMethod === "CREDITO"
                                        ? "border-brand bg-brand/5 text-foreground shadow-sm"
                                        : "border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-900 text-gray-600 dark:text-gray-400 hover:border-gray-300"
                                )}
                            >
                                <div className={cn("h-8 w-8 rounded-lg flex items-center justify-center transition-colors shadow-sm",
                                    paymentMethod === "CREDITO" ? "bg-gray-100 dark:bg-gray-800 text-foreground" : "bg-gray-50 dark:bg-gray-900 text-gray-500")}>
                                    <CreditCard className={cn("h-4 w-4", paymentMethod === "CREDITO" && "stroke-[2.5px]")} />
                                </div>
                                <span className="text-[9px] font-black uppercase tracking-tight italic">Crédito</span>
                            </button>

                            {/* DEBITO */}
                            <button
                                type="button"
