"use client";

import { useEffect, useState } from "react";
import { savePushSubscription } from "@/lib/actions/pushActions";

/*
    Hook simples para pedir permissão e registrar Service Worker de notificações web.
    Usado no _app ou no Layout principal, e chamado de preferência numa ação de usuário
    tipo "Acompanhar Pedido" ou após fazer o login / pedido com sucesso.
*/
export function usePushNotifications() {
    const [isSupported, setIsSupported] = useState(false);
    const [permission, setPermission] = useState<NotificationPermission>("default");

    useEffect(() => {
        if (typeof window !== "undefined" && "serviceWorker" in navigator && "PushManager" in window) {
            setIsSupported(true);
            setPermission(Notification.permission);
        }
    }, []);

    const urlBase64ToUint8Array = (base64String: string) => {
        const padding = '='.repeat((4 - base64String.length % 4) % 4);
        const base64 = (base64String + padding)
            .replace(/\-/g, '+')
            .replace(/_/g, '/');

        const rawData = window.atob(base64);
        const outputArray = new Uint8Array(rawData.length);

        for (let i = 0; i < rawData.length; ++i) {
            outputArray[i] = rawData.charCodeAt(i);
        }
        return outputArray;
    }

    const requestPermissionAndSubscribe = async () => {
        if (!isSupported) {
            console.log("Notificações não são suportadas neste navegador.");
            return false;
        }

        try {
            // 1. Pede a permissão (A janela nativa do browser sobe aqui)
            const result = await Notification.requestPermission();
            setPermission(result);

            if (result !== 'granted') {
                console.log("Permissão de notificação negada.");
                return false;
            }

            // 2. Registra o Roteador de Plano de Fundo (SW)
            const registration = await navigator.serviceWorker.register('/sw.js', {
                scope: '/'
            });

            // 3. Aguarda ele ficar ativo (caso instalou e tá Waiting)
            await navigator.serviceWorker.ready;

            // 4. Checa se o usuário já não está inscrito no próprio navegador
            let subscription = await registration.pushManager.getSubscription();

            if (!subscription) {
                // Se não, assina com nossa chave mestra pública (VAPID PUBLIC KEY) 
                // Essa chave precisa estar nas variáveis de ambiente (.env.local) e começar com NEXT_PUBLIC_...
                const vapidPublicKey = process.env.NEXT_PUBLIC_VAPID_PUBLIC_KEY;
                if (!vapidPublicKey) {
                    console.error("VAPID KEY não encontrada nas variáveis de ambiente");
                    return false;
                }

                const convertedVapidKey = urlBase64ToUint8Array(vapidPublicKey);

                subscription = await registration.pushManager.subscribe({
                    userVisibleOnly: true, // Obrigatório pelo Chrome
                    applicationServerKey: convertedVapidKey
                });
            }

            // 5. Salva na Nuvem (Supabase) via Server Action
            // Para não salvar infinito, do lado do servidor ele verifica se o record já existe.
            if (subscription) {
                await savePushSubscription(JSON.parse(JSON.stringify(subscription)));
            }

            return true;
        } catch (err) {
            console.error('Erro na Inscrição de Push:', err);
            return false;
        }
    };

    return {
        isSupported,
        permission,
        requestPermissionAndSubscribe
    };
}

"use server";

import { createClient } from "@/lib/supabase/server";
import { sendNotificationToUser } from "@/lib/actions/pushActions";

export async function getActiveOrders() {
    const supabase = await createClient();

    // Buscar pedidos com status ativo
    const { data: orders, error } = await supabase
        .from("active_orders")
        .select(`
      *,
      order_items (
        id,
        name,
        quantity,
        unit_price,
        notes,
        extras,
        product:products ( name )
      )
    `);

    if (error) {
        console.error("Erro ao buscar pedidos admin:", error);
        return [];
    }

    return orders || [];
}

export async function getManagementOrders() {
    const supabase = await createClient();

    const { data: orders, error } = await supabase
        .from("orders")
        .select(`
      *,
      order_items (
        id,
        name,
        quantity,
        unit_price,
        notes,
        extras,
        product:products ( name )
      )
    `)
        .order("created_at", { ascending: false }); // Mais novos primeiro

    if (error) {
        console.error("Erro ao buscar gestão de pedidos:", error);
        return [];
    }

    return orders || [];
}

export async function updateOrderStatus(orderId: string, newStatus: string, cancelReason?: string) {
    const supabase = await createClient();

    const updateData: any = { status: newStatus };
    if (cancelReason) {
        updateData.cancel_reason = cancelReason;
    }

    const { data: updatedOrder, error } = await supabase
        .from("orders")
        .update(updateData)
        .eq("id", orderId)
        .select("user_id")
        .single();

    if (error) {
        console.error(`Erro ao atualizar pedido ${orderId} para ${newStatus}:`, error);
        return { error: error.message };
    }

    if (updatedOrder && updatedOrder.user_id) {
        const { data: storeConfig } = await supabase
            .from("store_config")
            .select("store_name")
            .eq("id", 1)
            .single();

        const prefix = storeConfig?.store_name ? `${storeConfig.store_name}: ` : "";

        let title = "";
        let body = "";

        switch (newStatus) {
            case "PREPARING":
                title = `${prefix}👩‍🍳 Em Preparo!`;
                body = "Sua refeição já começou a ser preparada pela nossa cozinha.";
                break;
            case "READY":
                title = `${prefix}🛎️ Pronto!`;
                body = "Seu pedido está pronto para ser embalado e despachado.";
                break;
            case "DELIVERY":
                title = `${prefix}🛵 Saiu para Entrega!`;
                body = "O entregador já está a caminho com o seu pedido.";
                break;
            case "COMPLETED":
                title = `${prefix}✅ Entregue!`;
                body = "Aproveite sua refeição! Obrigado por pedir com a gente.";
                break;
        }

        if (title && body) {
            const url = `/order/${orderId}`;
            await sendNotificationToUser(updatedOrder.user_id, title, body, url);
        }
    }

    return { success: true };
}

"use server";

import { createClient } from "@/lib/supabase/server";
import { revalidatePath } from "next/cache";

async function checkAdmin() {
    const supabase = await createClient();
    const { data: authData } = await supabase.auth.getUser();
    if (!authData?.user) return false;

    const { data: profile } = await supabase
        .from("profiles")
        .select("is_admin")
        .eq("id", authData.user.id)
        .single();

    return profile?.is_admin === true;
}

// ===================== CATEGORIAS =====================

export async function createCategory(formData: FormData) {
    const isAdmin = await checkAdmin();
    if (!isAdmin) return { error: "Sem permissão." };

    const supabase = await createClient();
    const name = formData.get("name") as string;
    const station = formData.get("station") as string || "MAIN";

    // Busca o maior sort_order atual para adicionar ao final
    const { data: maxOrderData } = await supabase
        .from("categories")
        .select("sort_order")
        .order("sort_order", { ascending: false })
        .limit(1);

    const maxOrder = maxOrderData && maxOrderData.length > 0 ? maxOrderData[0].sort_order : -1;
    const nextOrder = maxOrder + 1;

    const { error } = await supabase
        .from("categories")
        .insert({ name, station, sort_order: nextOrder, is_active: true });

    if (error) return { error: error.message };

    revalidatePath("/admin/menu");
    revalidatePath("/");
    return { success: true };
}

export async function updateCategory(categoryId: string, newName: string, station: string = "MAIN") {
    const isAdmin = await checkAdmin();
    if (!isAdmin) return { error: "Sem permissão." };

    const supabase = await createClient();
    const { error } = await supabase
        .from("categories")
        .update({ name: newName, station })
        .eq("id", categoryId);

    if (error) return { error: error.message };

    revalidatePath("/admin/menu");
    revalidatePath("/");
    return { success: true };
}

export async function deleteCategory(categoryId: string) {
    const isAdmin = await checkAdmin();
    if (!isAdmin) return { error: "Sem permissão." };

    const supabase = await createClient();

    // Verifica se há produtos vinculados (não excluídos)
    const { data: linkedProducts } = await supabase
        .from("products")
        .select("id")
        .eq("category_id", categoryId)
        .is("deleted_at", null);

    if (linkedProducts && linkedProducts.length > 0) {
        return { error: `Não é possível excluir. Existem ${linkedProducts.length} produto(s) vinculado(s) a esta categoria.` };
    }

    const { error } = await supabase
        .from("categories")
        .update({ deleted_at: new Date().toISOString() })
        .eq("id", categoryId);

    if (error) return { error: error.message };

    revalidatePath("/admin/menu");
    revalidatePath("/");
    return { success: true };
}

export async function updateCategoryOrder(categoryId: string, direction: 'up' | 'down') {
    const isAdmin = await checkAdmin();
    if (!isAdmin) return { error: "Sem permissão." };

    const supabase = await createClient();

    // 1. Busca a categoria atual
    const { data: currentCat } = await supabase
        .from("categories")
        .select("id, sort_order")
        .eq("id", categoryId)
        .single();

    if (!currentCat) return { error: "Categoria não encontrada." };

    // 2. Busca a categoria vizinha
    const query = supabase
        .from("categories")
        .select("id, sort_order");

    if (direction === 'up') {
        query.lt("sort_order", currentCat.sort_order).order("sort_order", { ascending: false });
    } else {
        query.gt("sort_order", currentCat.sort_order).order("sort_order", { ascending: true });
    }

    const { data: neighbors } = await query.limit(1);
    const neighborCat = neighbors && neighbors.length > 0 ? neighbors[0] : null;

    if (!neighborCat) return { success: true }; // Já está no limite

    // 3. Troca os valores (usando um valor temporário negativo para evitar conflito se houvesse unique, mas aqui trocamos direto)
    const { error: err1 } = await supabase
        .from("categories")
        .update({ sort_order: neighborCat.sort_order })
        .eq("id", currentCat.id);

    const { error: err2 } = await supabase
        .from("categories")
        .update({ sort_order: currentCat.sort_order })
        .eq("id", neighborCat.id);

    if (err1 || err2) return { error: "Erro ao trocar ordem." };

    revalidatePath("/admin/menu");
    revalidatePath("/");
    return { success: true };
}

// ===================== PRODUTOS =====================

async function uploadProductImage(imageFile: File) {
    const supabase = await createClient();
    const fileExt = imageFile.name.split('.').pop();
    const fileName = `${Math.random().toString(36).substring(2, 15)}_${Date.now()}.${fileExt}`;
    const filePath = `products/${fileName}`;

    const { data, error } = await supabase.storage
        .from('product-images')
        .upload(filePath, imageFile);

    if (error) throw new Error(`Upload error: ${error.message}`);

    const { data: { publicUrl } } = supabase.storage
        .from('product-images')
        .getPublicUrl(filePath);

    return publicUrl;
}

export async function createProduct(formData: FormData) {
    const isAdmin = await checkAdmin();
    if (!isAdmin) return { error: "Sem permissão." };

    const supabase = await createClient();
    const name = formData.get("name") as string;
    const description = formData.get("description") as string;
    const priceText = formData.get("price") as string;
    const price = parseFloat(priceText.replace(",", "."));
    const category_id = formData.get("category_id") as string;

    // Suporte para upload de imagem ou URL
    let image_url = formData.get("image_url") as string;
    const imageFile = formData.get("image_file") as File;

    if (imageFile && imageFile.size > 0) {
        try {
            image_url = await uploadProductImage(imageFile);
        } catch (e: any) {
            return { error: e.message };
        }
    }

    const { error } = await supabase
        .from("products")
        .insert({
            name,
            description: description || null,
            price,
            category_id,
            image_url: image_url || null,
            is_available: true
        });

    if (error) return { error: error.message };

    revalidatePath("/admin/menu");
    revalidatePath("/");
    return { success: true };
}

export async function updateProduct(productId: string, formData: FormData) {
    const isAdmin = await checkAdmin();
    if (!isAdmin) return { error: "Sem permissão." };

    const supabase = await createClient();

    const name = formData.get("name") as string;
