    category_id: string;
    name: string;
    description: string | null;
    price: number;
    image_url: string | null;
    is_available: boolean;
    product_extras?: ProductExtra[];
}

import { isStoreOpen as checkStoreOpen } from "../storeUtils";

export async function getCatalog() {
    const supabase = await createClient()

    const { data: categories } = await supabase
        .from('categories')
        .select('*')
        .eq('is_active', true)
        .is('deleted_at', null)
        .order('sort_order', { ascending: true })

    const { data: products } = await supabase
        .from('products')
        .select(`
            *,
            product_extras (
                id,
                name,
                price
            )
        `)
        .eq('is_available', true)
        .is('deleted_at', null)
        .order('created_at', { ascending: false })

    const storeSettings = await obterConfiguracoesLoja();

    return {
        categories: (categories as Category[]) || [],
        products: (products as Product[]) || [],
        isStoreOpen: checkStoreOpen(storeSettings?.opening_hours),
        storeSettings
    }
}

// Versão admin que retorna TODOS os produtos (inclusive desativados)
export async function getAdminCatalog() {
    const supabase = await createClient()

    const { data: categories } = await supabase
        .from('categories')
        .select('*')
        .is('deleted_at', null)
        .order('sort_order', { ascending: true })

    const { data: products } = await supabase
        .from('products')
        .select(`
            *,
            product_extras (
                id,
                name,
                price
            )
        `)
        .is('deleted_at', null)
        .order('created_at', { ascending: false })

    return {
        categories: (categories as Category[]) || [],
        products: (products as Product[]) || []
    }
}

"use client";

import { DeliveryCalculationResult } from "./delivery.types";

export async function calculateDeliveryRemote({
    lat,
    lng,
    orderValue,
}: {
    lat: number;
    lng: number;
    orderValue: number;
}): Promise<DeliveryCalculationResult> {
    try {
        const response = await fetch("/api/delivery", {
            method: "POST",
            headers: {
                "Content-Type": "application/json",
            },
            body: JSON.stringify({ lat, lng, orderValue }),
        });

        // Lê como texto primeiro para evitar erro de JSON inválido/vazio
        const text = await response.text();
        if (!text || text.trim() === "") {
            throw new Error("Servidor retornou resposta vazia. Verifique as configurações do motor de entrega.");
        }

        let data: DeliveryCalculationResult;
        try {
            data = JSON.parse(text);
        } catch {
            throw new Error("Resposta inválida do servidor. Tente novamente.");
        }

        if (!response.ok) {
            throw new Error((data as any).error || `Erro ${response.status} ao calcular entrega`);
        }

        return data;
    } catch (error: any) {
        console.error("[DeliveryClient] Error:", error);
        return {
            zona: "Erro",
            distancia: 0,
            taxaEntrega: 0,
            freteGratis: false,
            pedidoMinimo: 0,
            tempoEstimadoMin: 0,
            error: error.message,
        };
    }
}

import { DeliveryCalculationResult } from "./delivery.types";
import { obterConfiguracoesLoja } from "@/lib/actions/adminSettingsActions";

export async function calculateDelivery({
    userLat,
    userLng,
    orderValue,
}: {
    userLat: number;
    userLng: number;
    orderValue: number;
}): Promise<DeliveryCalculationResult> {
    try {
        const config = await obterConfiguracoesLoja();

        const taxaFixa = config?.delivery_fee || 0;
        const pedidoMinimo = config?.min_order_value || 0;

        // Conversão de estimated_time (ex "40-50 min") para número inteiro aproximado 
        let tempoEstimado = 40;
        if (config?.estimated_time) {
            const match = config.estimated_time.match(/\d+/);
            if (match) tempoEstimado = parseInt(match[0], 10);
        }

        return {
            zona: "Taxa Fixa Padrão",
            distancia: 0, // Ignoramos a distância e zonas geográficas
            taxaEntrega: taxaFixa,
            freteGratis: taxaFixa === 0,
            pedidoMinimo: pedidoMinimo,
            tempoEstimadoMin: tempoEstimado,
        };
    } catch (error) {
        console.error("[DeliveryService] Error in calculation:", error);
        throw new Error("Erro ao calcular taxa de entrega.");
    }
}

import { Product } from "@/lib/services/catalogService";

export interface FavoritesStore {
    favoriteIds: string[];
    toggleFavorite: (productId: string) => void;
    isFavorite: (productId: string) => boolean;
}

import { create } from "zustand";
import { persist } from "zustand/middleware";

export const useFavoritesStore = create<FavoritesStore>()(
    persist(
        (set, get) => ({
            favoriteIds: [],
            toggleFavorite: (productId) => {
                const current = get().favoriteIds;
                const exists = current.includes(productId);

                if (exists) {
                    set({ favoriteIds: current.filter(id => id !== productId) });
                } else {
                    set({ favoriteIds: [...current, productId] });
                }
            },
            isFavorite: (productId) => {
                return get().favoriteIds.includes(productId);
            },
        }),
        {
            name: "rdos-favorites-storage",
        }
    )
);
